-- Player-centric effects for class and subclass traits.

CREATE TEMP TABLE _import_class_effect_data (
    trait_name TEXT NOT NULL,
    effect_name TEXT NOT NULL,
    description TEXT,
    effect_type TEXT NOT NULL,
    duration_text TEXT,
    requires_choice BOOLEAN NOT NULL DEFAULT FALSE,
    PRIMARY KEY (trait_name, effect_name)
) ON COMMIT DROP;

INSERT INTO _import_class_effect_data (trait_name, effect_name, description, effect_type, duration_text, requires_choice) VALUES
    ('Barbarian: Rage', 'Barbarian: Rage', 'You can imbue yourself with a primal power called Rage, a force that grants you extraordinary might and resilience. You can enter it as a Bonus Action if you aren’t wearing Heavy armor. You can enter your Rage the number of times shown for your Barbarian level in the Rages column of the Barbarian Features table. You regain one expended use when you finish a Short Rest, and you regain all expended uses when you finish a Long Rest. While active, your Rage follows the rules below. Damage Resistance. You have Resistance to Bludgeoning, Piercing, and Slashing damage. Rage Damage. When you make an attack using Strength—with either a weapon or an Unarmed Strike—and deal damage to the target, you gain a bonus to the damage that increases as you gain levels as a Barbarian, as shown in the Rage Damage column of the Barbarian Features table. Strength Advantage. You have Advantage on Strength checks and Strength saving throws. No Concentration or Spells. You can’t maintain Concentration, and you can’t cast spells. Duration. The Rage lasts until the end of your next turn, and it ends early if you don Heavy armor or have the Incapacitated condition. If your Rage is still active on your next turn, you can extend the Rage for another round by doing one of the following:
Make an attack roll against an enemy.
Force an enemy to make a saving throw.
Take a Bonus Action to extend your Rage. Each time the Rage is extended, it lasts until the end of your next turn. You can maintain a Rage for up to 10 minutes.', 'modifier', 'While active (10 minutes). Conditions: noHeavyArmor.', False),
    ('Barbarian: Unarmored Defense', 'Barbarian: Unarmored Defense', 'While you aren’t wearing any armor, your base Armor Class equals 10 plus your Dexterity and Constitution modifiers. You can use a Shield and still gain this benefit. (Add dexterity modifier and constitution modifier.)', 'modifier', 'Conditions: noArmor.', False),
    ('Barbarian: Weapon Mastery', 'Barbarian: Weapon Mastery', 'Your training with weapons allows you to use the mastery properties of two kinds of Simple or Martial Melee weapons of your choice. Whenever you finish a Long Rest, you can practice weapon drills and change one of those weapon choices. When you reach certain Barbarian levels, you gain the ability to use the mastery properties of more kinds of weapons, as shown in the Weapon Mastery column of the Barbarian Features table.', 'special', NULL, False),
    ('Barbarian: Danger Sense', 'Barbarian: Danger Sense', 'You gain an uncanny sense of when things aren’t as they should be, giving you an edge when you dodge perils. You have Advantage on Dexterity saving throws unless you have the Incapacitated condition.', 'modifier', NULL, False),
    ('Barbarian: Reckless Attack', 'Barbarian: Reckless Attack', 'You can throw aside all concern for defense to attack with increased ferocity. When you make your first attack roll on your turn, you can decide to attack recklessly. Doing so gives you Advantage on attack rolls using Strength until the start of your next turn, but attack rolls against you have Advantage during that time.', 'special', 'While active (until the start of your next turn).', False),
    ('Barbarian: Primal Knowledge', 'Barbarian: Primal Knowledge', 'You gain proficiency in another skill of your choice from the skill list available to Barbarians at level 1. In addition, while your Rage is active, you can channel primal power when you attempt certain tasks; whenever you make an ability check using one of the following skills, you can make it as a Strength check even if it normally uses a different ability: Acrobatics, Intimidation, Perception, Stealth, or Survival. When you use this ability, your Strength represents primal power coursing through you, honing your agility, bearing, and senses.', 'special', NULL, False),
    ('Barbarian: Extra Attack', 'Barbarian: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action on your turn.', 'special', NULL, False),
    ('Barbarian: Fast Movement', 'Barbarian: Fast Movement', 'Your speed increases by 10 feet while you are not wearing Heavy Armor.', 'modifier', 'Conditions: noHeavyArmor.', False),
    ('Barbarian: Feral Instinct', 'Barbarian: Feral Instinct', 'Your instincts are so honed that you have Advantage on Initiative rolls.', 'special', NULL, False),
    ('Barbarian: Instinctive Pounce', 'Barbarian: Instinctive Pounce', 'As part of the Bonus Action you take to enter your Rage, you can move up to half your Speed.', 'special', NULL, False),
    ('Barbarian: Brutal Strike', 'Barbarian: Brutal Strike', 'If you use Reckless Attack, you can forgo any Advantage on one Strength-based attack roll of your choice on your turn. The chosen attack roll mustn’t have Disadvantage. If the chosen attack roll hits, the target takes an extra 1d10 damage of the same type dealt by the weapon or Unarmed Strike, and you can cause one Brutal Strike effect of your choice. Forceful Blow. The target is pushed 15 feet straight away from you. You can then move up to half your Speed straight toward the target without provoking Opportunity Attacks. Hamstring Blow. The target’s Speed is reduced by 15 feet until the start of your next turn. A target can be affected by only one Hamstring Blow at a time—the most recent one.', 'special', NULL, False),
    ('Barbarian: Relentless Rage', 'Barbarian: Relentless Rage', 'Your Rage can keep you fighting despite grievous wounds. If you drop to 0 Hit Points while your Rage is active and don’t die outright, you can make a DC 10 Constitution saving throw. If you succeed, your Hit Points instead change to a number equal to twice your Barbarian level. Each time you use this feature after the first, the DC increases by 5. When you finish a Short or Long Rest, the DC resets to 10.', 'special', NULL, False),
    ('Barbarian: Improved Brutal Strike', 'Barbarian: Improved Brutal Strike', 'The extra damage of your Brutal Strike increases to 2d10. In addition, you can use two different Brutal Strike effects whenever you use your Brutal Strike feature.', 'special', NULL, False),
    ('Barbarian: Persistent Rage', 'Barbarian: Persistent Rage', 'When you roll Initiative, you can regain all expended uses of Rage. After you regain uses of Rage in this way, you can’t do so again until you finish a Long Rest. In addition, your Rage is so fierce that it now lasts for 10 minutes without you needing to do anything to extend it from round to round. Your Rage ends early if you have the Unconscious condition (not just the Incapacitated condition) or don Heavy armor.', 'special', NULL, False),
    ('Barbarian: Indomitable Might', 'Barbarian: Indomitable Might', 'If your total for a Strength check or Strength saving throw is less than your Strength score, you can use that score in place of the total.', 'special', NULL, False),
    ('Barbarian: Epic Boon', 'Barbarian: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Barbarian: Primal Champion', 'Barbarian: Primal Champion', 'You embody primal power. Your Strength and Constitution scores increase by 4, and their maximum is now 25.', 'special', NULL, False),
    ('Barbarian (Path of the Berserker): Frenzy', 'Barbarian (Path of the Berserker): Frenzy', 'If you use Reckless Attack while your Rage is active, you deal extra damage to the first target you hit on your turn with a Strength-based attack. To determine the extra damage, roll a number of d6s equal to your Rage Damage bonus, and add them together. The damage has the same type as the weapon or Unarmed Strike used for the attack.', 'special', NULL, False),
    ('Barbarian (Path of the Berserker): Mindless Rage', 'Barbarian (Path of the Berserker): Mindless Rage', 'You are immune to the Charmed and Frightened conditions while your Rage is active. If you are Charmed or Frightened when you enter your Rage, the condition is suspended for the duration of the Rage.', 'special', NULL, False),
    ('Barbarian (Path of the Berserker): Retaliation', 'Barbarian (Path of the Berserker): Retaliation', 'Starting at 10th level, when you take damage from a creature that is within 5 feet of you, you can use your Reaction to make one melee attack against that creature with a weapon or an Unarmed Strike.', 'special', NULL, False),
    ('Barbarian (Path of the Berserker): Intimidating Presence', 'Barbarian (Path of the Berserker): Intimidating Presence', 'As a Bonus Action, you can threaten nearby creatures. Each creature of your choice in a 30-foot Emanation must succeed on a Wisdom saving throw (DC 8 + your Strength modifier + your Proficiency Bonus) or have the Frightened condition for 1 minute. A frightened creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. Once you use this feature, you can''t use it again until you finish a Long Rest. You can also restore your use of this feature by expending one use of your Rage (no action required).', 'special', NULL, False),
    ('Barbarian (Path of the Wild Heart): Animal Speaker', 'Barbarian (Path of the Wild Heart): Animal Speaker', 'You can cast the Beast Sense and Speak with Animals spells, but only as rituals. Wisdom is your spellcasting ability for these spells.', 'special', NULL, False),
    ('Barbarian (Path of the Wild Heart): Rage of the Wilds', 'Barbarian (Path of the Wild Heart): Rage of the Wilds', 'You channel the power of a beast. Whenever you enter your Rage, choose one of the following options: Bear. While your Rage is active, you have Resistance to all damage types except Force, Necrotic, Psychic, and Radiant. Eagle. When you enter your Rage, and as a Bonus Action while your Rage is active, you can take both the Dash and Disengage actions. Wolf. While your Rage is active, your allies have Advantage on melee attack rolls against any enemy within 5 feet of you that is not Incapacitated.', 'special', NULL, False),
    ('Barbarian (Path of the Wild Heart): Aspect of the Wilds', 'Barbarian (Path of the Wild Heart): Aspect of the Wilds', 'You gain an aspect of a beast. Whenever you finish a Long Rest, choose one of the following options, which lasts until you finish your next Long Rest: Owl. You gain Darkvision with a range of 60 feet. If you already have Darkvision, its range increases by 60 feet. Panther. You gain a Climb Speed equal to your Speed. Salmon. You gain a Swim Speed equal to your Speed.', 'special', NULL, False),
    ('Barbarian (Path of the Wild Heart): Nature Speaker', 'Barbarian (Path of the Wild Heart): Nature Speaker', 'You can cast the Commune with Nature spell, but only as a ritual. Wisdom is your spellcasting ability for this spell.', 'special', NULL, False),
    ('Barbarian (Path of the Wild Heart): Power of the Wilds', 'Barbarian (Path of the Wild Heart): Power of the Wilds', 'You channel a magical aspect of a beast. Whenever you enter your Rage, choose one of the following options: Falcon. While you aren''t wearing armor, you gain a Fly Speed equal to your Speed. Lion. While your Rage is active, any enemy within 5 feet of you has Disadvantage on attack rolls against targets other than you or another character with this feature. Ram. While your Rage is active, if you hit a Large or smaller creature with a melee attack, you can knock the target Prone.', 'special', NULL, False),
    ('Barbarian (Path of the World Tree): Vitality of the Tree', 'Barbarian (Path of the World Tree): Vitality of the Tree', 'When you enter your Rage, you gain Temporary Hit Points equal to your Barbarian level. At the start of each of your turns while your Rage is active, you can choose another creature within 10 feet of yourself. That creature gains Temporary Hit Points equal to your Rage Damage bonus, which last until the start of your next turn.', 'special', NULL, False),
    ('Barbarian (Path of the World Tree): Branches of the Tree', 'Barbarian (Path of the World Tree): Branches of the Tree', 'While your Rage is active, when a creature you can see starts its turn within 30 feet of you, you can use your Reaction to summon spectral branches. The target must succeed on a Strength saving throw (DC 8 + your Strength modifier + your Proficiency Bonus) or be teleported to an unoccupied space you choose within 5 feet of yourself. Alternatively, you can teleport the willing target to that space without a saving throw. If the target fails the save (or is willing), its Speed is reduced to 0 until the end of the current turn.', 'special', NULL, False),
    ('Barbarian (Path of the World Tree): Battering Roots', 'Barbarian (Path of the World Tree): Battering Roots', 'During your turn, the reach for your melee attacks with weapons that have the Heavy or Versatile property is 10 feet greater than normal. In addition, when you hit with such a weapon on your turn, you can activate its Push or Topple property even if you don''t have that property active for the weapon.', 'special', NULL, False),
    ('Barbarian (Path of the World Tree): Travel Along the Tree', 'Barbarian (Path of the World Tree): Travel Along the Tree', 'When you enter your Rage and as a Bonus Action while your Rage is active, you can teleport up to 60 feet to an unoccupied space you can see. Once per Rage, you can increase this teleport''s range to 150 feet. When you do so, you can also bring up to six willing creatures of Medium size or smaller that are within 10 feet of you. Each creature is teleported to an unoccupied space of your choice within 10 feet of your destination space.', 'special', NULL, False),
    ('Barbarian (Path of the Zealot): Divine Fury', 'Barbarian (Path of the Zealot): Divine Fury', 'While your Rage is active, you can channel divine fury into your weapon strikes. The first creature you hit on each of your turns with a weapon or an Unarmed Strike takes extra damage. The extra damage is 1d6 plus half your Barbarian level (round down). The extra damage is Necrotic or Radiant (your choice when you hit the target).', 'special', NULL, False),
    ('Barbarian (Path of the Zealot): Warrior of the Gods', 'Barbarian (Path of the Zealot): Warrior of the Gods', 'A divine power protects you and others. You have a pool of d12s that you can use to restore Hit Points. The pool''s total number of dice equals your Barbarian level. As a Bonus Action, you can spend dice from the pool to heal yourself or a creature within 5 feet of you. Roll the spent dice, and the target regains a number of Hit Points equal to the roll''s total.', 'special', NULL, False),
    ('Barbarian (Path of the Zealot): Fanatical Focus', 'Barbarian (Path of the Zealot): Fanatical Focus', 'If you fail a saving throw while your Rage is active, you can reroll it, and you must use the new roll. You gain a bonus to the new roll equal to your Rage Damage bonus. Once you use this feature, you can''t use it again until you enter a new Rage.', 'special', NULL, False),
    ('Barbarian (Path of the Zealot): Zealous Presence', 'Barbarian (Path of the Zealot): Zealous Presence', 'As a Bonus Action, you unleash a battle cry infused with divine energy. Up to ten other creatures of your choice within 60 feet of you gain Advantage on attack rolls and saving throws until the start of your next turn. Once you use this feature, you can''t use it again until you finish a Long Rest. You can also restore your use of this feature by expending one use of your Rage (no action required).', 'special', 'While active (1 round).', False),
    ('Barbarian (Path of the Zealot): Rage of the Gods', 'Barbarian (Path of the Zealot): Rage of the Gods', 'Your Rage becomes a manifest beacon of divine power. While your Rage is active, you gain the following benefits: Fly Speed. You gain a Fly Speed equal to your Speed, and you can hover. Resistances. You have Resistance to Necrotic, Psychic, and Radiant damage. Defy Death. If a creature you can see within 30 feet of you (including yourself) would drop to 0 Hit Points, you can use your Reaction to prevent it from doing so. The creature instead drops to 1 Hit Point.', 'damage_adjustment', NULL, False),
    ('Bard: Bardic Inspiration', 'Bard: Bardic Inspiration', 'Bonus Action to grant one creature within 60 feet a Bardic Inspiration die it can add after failing a D20 Test, potentially turning the failure into a success.', 'special', 'While active (1 hour).', False),
    ('Bard: Spellcasting', 'Bard: Spellcasting', 'Cast prepared Bard spells using Charisma. You start with two Bard cantrips and four level 1 prepared spells, and use a Musical Instrument as a spellcasting focus.', 'special', NULL, False),
    ('Bard: Expertise', 'Bard: Expertise', 'Choose two more skill proficiencies for Expertise.', 'special', NULL, False),
    ('Bard: Jack of All Trades', 'Bard: Jack of All Trades', 'Add half your Proficiency Bonus to ability checks using skills you lack proficiency in.', 'special', NULL, False),
    ('Bard: Font of Inspiration', 'Bard: Font of Inspiration', 'Regain Bardic Inspiration uses on a Short or Long Rest, and spend a spell slot to regain one use.', 'special', NULL, False),
    ('Bard: Countercharm', 'Bard: Countercharm', 'Reaction when you or a creature within 30 feet fails a save against Charmed or Frightened; force a reroll with Advantage.', 'special', NULL, False),
    ('Bard: Magical Secrets', 'Bard: Magical Secrets', 'When your prepared spell count increases or you replace a Bard spell, you can choose from the Bard, Cleric, Druid, and Wizard spell lists.', 'special', NULL, False),
    ('Bard: Superior Inspiration', 'Bard: Superior Inspiration', 'When you roll Initiative, regain Bardic Inspiration uses until you have two if you have fewer than two.', 'special', NULL, False),
    ('Bard: Epic Boon', 'Bard: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Bard: Words of Creation', 'Bard: Words of Creation', 'Always prepare Power Word Heal and Power Word Kill. When you cast either spell, you can also target a second creature within 10 feet of the first.', 'special', NULL, False),
    ('Bard (College of Dance): Dazzling Footwork', 'Bard (College of Dance): Dazzling Footwork', 'While unarmored and not using a Shield, gain dance-based Performance Advantage, AC = 10 + Dex + Cha, and enhanced Unarmed Strikes tied to your Bardic Inspiration die.', 'modifier', 'Conditions: no_armor.', False),
    ('Bard (College of Dance): Inspiring Movement', 'Bard (College of Dance): Inspiring Movement', 'When a visible enemy ends its turn within 5 feet, expend Bardic Inspiration as a Reaction to move yourself and one nearby ally up to half Speed without Opportunity Attacks.', 'special', NULL, False),
    ('Bard (College of Dance): Tandem Footwork', 'Bard (College of Dance): Tandem Footwork', 'When rolling Initiative, expend Bardic Inspiration to add the die roll to your Initiative and nearby allies who can see or hear you.', 'special', NULL, False),
    ('Bard (College of Dance): Leading Evasion', 'Bard (College of Dance): Leading Evasion', 'Against effects allowing a Dexterity save for half damage, take none on a success and half on a failure; nearby creatures making the same save can share this benefit.', 'special', NULL, False),
    ('Bard (College of Glamour): Beguiling Magic', 'Bard (College of Glamour): Beguiling Magic', 'Always prepare Charm Person and Mirror Image. After casting an Enchantment or Illusion spell with a slot, try to Charm or Frighten a visible creature; refresh after a Long Rest or by spending Bardic Inspiration.', 'special', NULL, False),
    ('Bard (College of Glamour): Mantle of Inspiration', 'Bard (College of Glamour): Mantle of Inspiration', 'Bonus Action to expend Bardic Inspiration, grant Temporary Hit Points to nearby creatures, and let each move as a Reaction without Opportunity Attacks.', 'special', NULL, False),
    ('Bard (College of Glamour): Mantle of Majesty', 'Bard (College of Glamour): Mantle of Majesty', 'Always prepare Command. As a Bonus Action, cast it without a slot and keep casting it as a Bonus Action for 1 minute while concentrating; refresh with a Long Rest or a level 3+ spell slot.', 'special', 'While active (1 minute).', False),
    ('Bard (College of Glamour): Unbreakable Majesty', 'Bard (College of Glamour): Unbreakable Majesty', 'Bonus Action to assume a majestic presence; the first attacker to hit you each turn must pass a Charisma save or miss.', 'special', 'While active (1 minute).', False),
    ('Bard (College of Lore): Bonus Proficiencies', 'Bard (College of Lore): Bonus Proficiencies', 'You gain proficiency with three skills of your choice.', 'special', NULL, False),
    ('Bard (College of Lore): Cutting Words', 'Bard (College of Lore): Cutting Words', 'Reaction to expend Bardic Inspiration and subtract the die from a visible creature''s damage roll, successful ability check, or successful attack roll.', 'special', NULL, False),
    ('Bard (College of Lore): Magical Discoveries', 'Bard (College of Lore): Magical Discoveries', 'Choose two always-prepared spells from the Cleric, Druid, or Wizard spell lists; they must be cantrips or spells you can cast with your slots.', 'special', NULL, False),
    ('Bard (College of Lore): Peerless Skill', 'Bard (College of Lore): Peerless Skill', 'When you fail an ability check or attack roll, expend Bardic Inspiration to add the die and potentially succeed; keep the use if you still fail.', 'special', NULL, False),
    ('Bard (College of Valor): Combat Inspiration', 'Bard (College of Valor): Combat Inspiration', 'Allies can use your Bardic Inspiration to add to damage or AC against an attack.', 'special', NULL, False),
    ('Bard (College of Valor): Martial Training', 'Bard (College of Valor): Martial Training', 'Gain proficiency with Medium Armor, Shields, and Martial Weapons. Use a weapon as a spell focus.', 'special', NULL, False),
    ('Bard (College of Valor): Extra Attack', 'Bard (College of Valor): Extra Attack', 'You can attack twice. You can replace one of these attacks with a Cantrip.', 'special', NULL, False),
    ('Bard (College of Valor): Battle Magic', 'Bard (College of Valor): Battle Magic', 'When you use an Action to cast a spell, you can make one weapon attack as a Bonus Action.', 'special', NULL, False),
    ('Cleric: Divine Order', 'Cleric: Divine Order', 'Choose Protector for Martial weapons and Heavy armor, or Thaumaturge for one extra Cleric cantrip and a Wisdom-based bonus to Arcana or Religion checks.', 'proficiency', NULL, True),
    ('Cleric: Spellcasting', 'Cleric: Spellcasting', 'Cast prepared Cleric spells using Wisdom. You start with three Cleric cantrips and four level 1 prepared spells, and use a Holy Symbol as a spellcasting focus.', 'special', NULL, False),
    ('Cleric: Channel Divinity', 'Cleric: Channel Divinity', 'Channel divine energy to fuel effects such as Divine Spark, Turn Undead, and subclass options. Regain uses on rests as shown by your Cleric level.', 'special', NULL, False),
    ('Cleric: Divine Spark', 'Cleric: Divine Spark', 'Magic Action to target a visible creature within 30 feet, either healing it or forcing a Constitution save against Necrotic or Radiant damage.', 'special', NULL, False),
    ('Cleric: Turn Undead', 'Cleric: Turn Undead', 'Magic Action using Channel Divinity to force chosen Undead within 30 feet to make a Wisdom save or become Frightened and Incapacitated for 1 minute.', 'special', 'While active (1 minute).', False),
    ('Cleric: Sear Undead', 'Cleric: Sear Undead', 'When you use Turn Undead, roll d8s equal to your Wisdom modifier (minimum one). Undead that fail the save take Radiant damage equal to the total without ending Turn Undead.', 'special', NULL, False),
    ('Cleric: Blessed Strikes', 'Cleric: Blessed Strikes', 'Choose Divine Strike for extra Necrotic or Radiant weapon damage, or Potent Spellcasting to add Wisdom to Cleric cantrip damage.', 'special', NULL, True),
    ('Cleric: Divine Intervention', 'Cleric: Divine Intervention', 'Magic Action to cast a Cleric spell of level 5 or lower without a spell slot or Material components, provided it does not require a Reaction.', 'special', NULL, False),
    ('Cleric: Improved Blessed Strikes', 'Cleric: Improved Blessed Strikes', 'Your Blessed Strikes choice improves: Divine Strike deals 2d8 extra damage, or Potent Spellcasting grants Temporary Hit Points after damaging with a Cleric cantrip.', 'special', NULL, False),
    ('Cleric: Epic Boon', 'Cleric: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Cleric: Greater Divine Intervention', 'Cleric: Greater Divine Intervention', 'When you use Divine Intervention, you can choose Wish. If you do, you cannot use Divine Intervention again until you finish 2d4 Long Rests.', 'special', NULL, False),
    ('Cleric (Life Domain): Disciple of Life', 'Cleric (Life Domain): Disciple of Life', 'When a spell you cast with a spell slot restores HP, the target regains extra HP equal to 2 plus the spell slot level.', 'special', NULL, False),
    ('Cleric (Life Domain): Life Domain Spells', 'Cleric (Life Domain): Life Domain Spells', 'Always prepare Aid, Bless, Cure Wounds, and Lesser Restoration; later add Mass Healing Word, Revivify, Aura of Life, Death Ward, Greater Restoration, and Mass Cure Wounds.', 'special', NULL, False),
    ('Cleric (Life Domain): Preserve Life', 'Cleric (Life Domain): Preserve Life', 'Magic Action using Channel Divinity to restore HP equal to 5 times your Cleric level, divided among Bloodied creatures within 30 feet and not above half HP.', 'special', NULL, False),
    ('Cleric (Life Domain): Blessed Healer', 'Cleric (Life Domain): Blessed Healer', 'After you cast a spell with a spell slot that restores HP to another creature, you regain HP equal to 2 plus the spell slot level.', 'special', NULL, False),
    ('Cleric (Life Domain): Supreme Healing', 'Cleric (Life Domain): Supreme Healing', 'When you would roll dice to restore HP with a spell or Channel Divinity, use the highest possible result for each die instead.', 'special', NULL, False),
    ('Cleric (Light Domain): Light Domain Spells', 'Cleric (Light Domain): Light Domain Spells', 'Always prepare Burning Hands, Faerie Fire, Scorching Ray, and See Invisibility; later add Daylight, Fireball, Arcane Eye, Wall of Fire, Flame Strike, and Scrying.', 'special', NULL, False),
    ('Cleric (Light Domain): Radiance of the Dawn', 'Cleric (Light Domain): Radiance of the Dawn', 'Magic Action using Channel Divinity to dispel magical Darkness and deal Radiant damage in a 30-foot Emanation.', 'special', NULL, False),
    ('Cleric (Light Domain): Warding Flare', 'Cleric (Light Domain): Warding Flare', 'Reaction when a visible creature within 30 feet makes an attack roll, imposing Disadvantage on that roll. Uses equal Wisdom modifier per Long Rest.', 'special', NULL, False),
    ('Cleric (Light Domain): Improved Warding Flare', 'Cleric (Light Domain): Improved Warding Flare', 'Regain Warding Flare uses on Short or Long Rest, and grant Temporary Hit Points to the target of the triggering attack when you use it.', 'special', NULL, False),
    ('Cleric (Light Domain): Corona of Light', 'Cleric (Light Domain): Corona of Light', 'Magic Action to emit sunlight for 1 minute. Enemies in the bright light have Disadvantage on saves against Radiance of the Dawn and Fire or Radiant spells.', 'special', 'While active (1 minute).', False),
    ('Cleric (Trickery Domain): Blessing of the Trickster', 'Cleric (Trickery Domain): Blessing of the Trickster', 'Magic Action to give yourself or a willing creature within 30 feet Advantage on Stealth checks until your next Long Rest or until you use this feature again.', 'special', 'While active (Until your next Long Rest).', False),
    ('Cleric (Trickery Domain): Invoke Duplicity', 'Cleric (Trickery Domain): Invoke Duplicity', 'Bonus Action using Channel Divinity to create an illusory duplicate for 1 minute. Cast from its space, distract nearby enemies, and move it as a Bonus Action.', 'special', 'While active (1 minute).', False),
    ('Cleric (Trickery Domain): Trickery Domain Spells', 'Cleric (Trickery Domain): Trickery Domain Spells', 'Always prepare Charm Person, Disguise Self, Invisibility, and Pass without Trace; later add Hypnotic Pattern, Nondetection, Confusion, Dimension Door, Dominate Person, and Modify Memory.', 'special', NULL, False),
    ('Cleric (Trickery Domain): Trickster''s Transposition', 'Cleric (Trickery Domain): Trickster''s Transposition', 'Whenever you create or move your Invoke Duplicity illusion as a Bonus Action, you can teleport by swapping places with it.', 'special', NULL, False),
    ('Cleric (Trickery Domain): Improved Duplicity', 'Cleric (Trickery Domain): Improved Duplicity', 'Your Invoke Duplicity illusion grants allies Advantage against nearby enemies and heals a nearby creature when the illusion ends.', 'special', NULL, False),
    ('Cleric (War Domain): Guided Strike', 'Cleric (War Domain): Guided Strike', 'When you or a creature within 30 feet misses with an attack roll, expend Channel Divinity to add +10, using your Reaction if the roll is not yours.', 'special', NULL, False),
    ('Cleric (War Domain): War Domain Spells', 'Cleric (War Domain): War Domain Spells', 'Always prepare Guiding Bolt, Magic Weapon, Shield of Faith, and Spiritual Weapon; later add Crusader''s Mantle, Spirit Guardians, Fire Shield, Freedom of Movement, Hold Monster, and Steel Wind Strike.', 'special', NULL, False),
    ('Cleric (War Domain): War Priest', 'Cleric (War Domain): War Priest', 'Bonus Action to make one weapon attack or Unarmed Strike. Uses equal Wisdom modifier per Short or Long Rest.', 'special', NULL, False),
    ('Cleric (War Domain): War God''s Blessing', 'Cleric (War Domain): War God''s Blessing', 'Expend Channel Divinity to cast Shield of Faith or Spiritual Weapon without a spell slot or Concentration; the spell lasts 1 minute.', 'special', 'While active (1 minute).', False),
    ('Cleric (War Domain): Avatar of Battle', 'Cleric (War Domain): Avatar of Battle', 'Gain Resistance to Bludgeoning, Piercing, and Slashing damage.', 'damage_adjustment', NULL, False),
    ('Druid: Druidic', 'Druid: Druidic', 'You know Druidic and always have Speak with Animals prepared. You can also leave hidden messages that other Druidic speakers automatically understand.', 'special', NULL, False),
    ('Druid: Primal Order', 'Druid: Primal Order', 'Choose Magician for one extra Druid cantrip and a Wisdom-based bonus to Arcana or Nature checks, or Warden for Martial weapons and Medium armor.', 'proficiency', NULL, True),
    ('Druid: Spellcasting', 'Druid: Spellcasting', 'Cast prepared Druid spells using Wisdom. You start with two Druid cantrips and four level 1 prepared spells, and use a Druidic Focus as a spellcasting focus.', 'special', NULL, False),
    ('Druid: Wild Companion', 'Druid: Wild Companion', 'Magic Action to expend a spell slot or a Wild Shape use to cast Find Familiar without Material components; the familiar is Fey and disappears after your next Long Rest.', 'special', NULL, False),
    ('Druid: Wild Shape', 'Druid: Wild Shape', 'Bonus Action to assume a known Beast form for hours equal to half your Druid level. Gain Temporary Hit Points equal to your Druid level and use known forms by level.', 'special', 'While active ({halfLevel} hours).', False),
    ('Druid: Wild Resurgence', 'Druid: Wild Resurgence', 'Once on each of your turns, if you have no Wild Shape uses left, you can expend a spell slot to regain one use. Once per Long Rest, expend one Wild Shape use to regain a level 1 spell slot.', 'special', NULL, False),
    ('Druid: Elemental Fury', 'Druid: Elemental Fury', 'Choose Potent Spellcasting to add Wisdom to Druid cantrip damage, or Primal Strike to add 1d8 Cold, Fire, Lightning, or Thunder damage to a weapon or Wild Shape attack once per turn.', 'special', NULL, True),
    ('Druid: Improved Elemental Fury', 'Druid: Improved Elemental Fury', 'Your Elemental Fury choice improves: Potent Spellcasting increases long-range Druid cantrip range, or Primal Strike deals 2d8 extra damage.', 'special', NULL, False),
    ('Druid: Beast Spells', 'Druid: Beast Spells', 'While in Wild Shape, you can cast spells except those with costly or consumed Material components.', 'special', NULL, False),
    ('Druid: Epic Boon', 'Druid: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Druid: Archdruid', 'Druid: Archdruid', 'Regain one Wild Shape use when rolling Initiative with none left, convert Wild Shape uses into a spell slot once per Long Rest, and age more slowly.', 'special', NULL, False),
    ('Druid (Circle of the Land): Circle of the Land Spells', 'Druid (Circle of the Land): Circle of the Land Spells', 'After each Long Rest, choose Arid, Polar, Temperate, or Tropical land; you always prepare that land''s spells for your Druid level and lower.', 'special', NULL, False),
    ('Druid (Circle of the Land): Land''s Aid', 'Druid (Circle of the Land): Land''s Aid', 'Magic Action to expend Wild Shape, creating a 10-foot-radius burst within 60 feet. Chosen creatures take Necrotic damage, and one creature in the area regains HP.', 'special', NULL, False),
    ('Druid (Circle of the Land): Natural Recovery', 'Druid (Circle of the Land): Natural Recovery', 'Cast one prepared Circle spell without a slot once per Long Rest, and recover spell slots after a Short Rest with combined level up to half your Druid level.', 'special', NULL, False),
    ('Druid (Circle of the Land): Nature''s Ward', 'Druid (Circle of the Land): Nature''s Ward', 'You are immune to the Poisoned condition and gain Resistance tied to your current land choice: Fire, Cold, Lightning, or Poison.', 'special', NULL, False),
    ('Druid (Circle of the Land): Nature''s Sanctuary', 'Druid (Circle of the Land): Nature''s Sanctuary', 'Magic Action to expend Wild Shape and create a protective cube of spectral trees and vines. You and allies gain Half Cover, and allies share your Nature''s Ward Resistance.', 'special', 'While active (1 minute).', False),
    ('Druid (Circle of the Moon): Circle Forms', 'Druid (Circle of the Moon): Circle Forms', 'Your Wild Shape forms can have CR up to one-third your Druid level, your Beast AC can become 13 + Wisdom modifier, and you gain triple Druid level Temporary Hit Points.', 'modifier', NULL, False),
    ('Druid (Circle of the Moon): Circle of the Moon Spells', 'Druid (Circle of the Moon): Circle of the Moon Spells', 'Always prepare Cure Wounds, Moonbeam, and Starry Wisp; later add Conjure Animals, Fount of Moonlight, and Mass Cure Wounds. You can cast these spells in Wild Shape.', 'special', NULL, False),
    ('Druid (Circle of the Moon): Improved Circle Forms', 'Druid (Circle of the Moon): Improved Circle Forms', 'In Wild Shape, your attacks can deal Radiant damage instead of their normal type, and you add Wisdom to Constitution saves.', 'special', NULL, False),
    ('Druid (Circle of the Moon): Moonlight Step', 'Druid (Circle of the Moon): Moonlight Step', 'Bonus Action to teleport up to 30 feet to a visible unoccupied space and gain Advantage on your next attack roll before the end of the turn.', 'special', NULL, False),
    ('Druid (Circle of the Moon): Lunar Form', 'Druid (Circle of the Moon): Lunar Form', 'Once per turn, deal extra Radiant damage with a Wild Shape attack. When you use Moonlight Step, you can teleport one nearby willing creature with you.', 'special', NULL, False),
    ('Druid (Circle of the Sea): Circle of the Sea Spells', 'Druid (Circle of the Sea): Circle of the Sea Spells', 'Always prepare Fog Cloud, Gust of Wind, Ray of Frost, Shatter, and Thunderwave; later add Lightning Bolt, Water Breathing, Control Water, Ice Storm, Conjure Elemental, and Hold Monster.', 'special', NULL, False),
    ('Druid (Circle of the Sea): Wrath of the Sea', 'Druid (Circle of the Sea): Wrath of the Sea', 'Bonus Action to expend Wild Shape and manifest a 5-foot Emanation for 10 minutes. It can deal Cold damage equal to Wisdom modifier d6s and push Large or smaller targets 15 feet.', 'special', 'While active (10 minutes).', False),
    ('Druid (Circle of the Sea): Aquatic Affinity', 'Druid (Circle of the Sea): Aquatic Affinity', 'Your Wrath of the Sea Emanation grows to 10 feet, and you gain a Swim Speed equal to your Speed.', 'special', NULL, False),
    ('Druid (Circle of the Sea): Stormborn', 'Druid (Circle of the Sea): Stormborn', 'While Wrath of the Sea is active, you gain a Fly Speed equal to your Speed and Resistance to Cold, Lightning, and Thunder damage.', 'damage_adjustment', NULL, False),
    ('Druid (Circle of the Sea): Oceanic Gift', 'Druid (Circle of the Sea): Oceanic Gift', 'You can manifest Wrath of the Sea around a willing creature within 60 feet, or around both that creature and yourself by expending two Wild Shape uses.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Star Map', 'Druid (Circle of the Stars): Star Map', 'Create a star chart that can be a Druidic Focus. While holding it, you always prepare Guidance and Guiding Bolt and can cast Guiding Bolt without a spell slot.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Starry Form', 'Druid (Circle of the Stars): Starry Form', 'Bonus Action to expend Wild Shape and take a luminous form for 10 minutes, choosing Archer for radiant attacks, Chalice for extra healing, or Dragon for reliable Wisdom, Intelligence, and Concentration checks.', 'special', 'While active (10 minutes).', False),
    ('Druid (Circle of the Stars): Starry Form: Archer', 'Druid (Circle of the Stars): Starry Form: Archer', 'While your Archer constellation is active, make a radiant ranged spell attack as a Bonus Action.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Starry Form: Chalice', 'Druid (Circle of the Stars): Starry Form: Chalice', 'While your Chalice constellation is active, your healing spells restore additional hit points.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Starry Form: Dragon', 'Druid (Circle of the Stars): Starry Form: Dragon', 'While your Dragon constellation is active, your mind and concentration are steadied by starlight.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Cosmic Omen', 'Druid (Circle of the Stars): Cosmic Omen', 'After each Long Rest, consult your Star Map. Until your next Long Rest, use a Reaction to add or subtract 1d6 from a visible creature''s D20 Test depending on the omen.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Starry Form: Dragon Flight', 'Druid (Circle of the Stars): Starry Form: Dragon Flight', 'Your Dragon constellation grants flight while active.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Twinkling Constellations', 'Druid (Circle of the Stars): Twinkling Constellations', 'Your Starry Form improves: Archer and Chalice use 2d8, Dragon gains a 20-foot Fly Speed with hover, and you can change constellation at the start of each turn.', 'special', NULL, False),
    ('Druid (Circle of the Stars): Full of Stars', 'Druid (Circle of the Stars): Full of Stars', 'While in Starry Form, you have resistance to Bludgeoning, Piercing, and Slashing damage.', 'damage_adjustment', NULL, False),
    ('Fighter: Fighting Style', 'Fighter: Fighting Style', 'Gain a Fighting Style feat of your choice. Whenever you gain a Fighter level, you can replace it with another Fighting Style feat.', 'special', NULL, True),
    ('Fighter: Second Wind', 'Fighter: Second Wind', 'Bonus Action to regain HP equal to 1d10 + your Fighter level. Uses recover on Short and Long Rests and increase at higher Fighter levels.', 'special', NULL, False),
    ('Fighter: Weapon Mastery', 'Fighter: Weapon Mastery', 'Use mastery properties for three Simple or Martial weapons, changing one choice after each Long Rest. More weapon choices unlock at higher Fighter levels.', 'special', NULL, False),
    ('Fighter: Action Surge', 'Fighter: Action Surge', 'On your turn, take one additional action except the Magic action. Refresh after a Short or Long Rest.', 'special', NULL, False),
    ('Fighter: Tactical Mind', 'Fighter: Tactical Mind', 'When you fail an ability check, expend Second Wind to add 1d10 to the roll. If the check still fails, the Second Wind use is not spent.', 'special', NULL, False),
    ('Fighter: Extra Attack', 'Fighter: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action.', 'special', NULL, False),
    ('Fighter: Tactical Shift', 'Fighter: Tactical Shift', 'Whenever you activate Second Wind as a Bonus Action, move up to half your Speed without provoking Opportunity Attacks.', 'special', NULL, False),
    ('Fighter: Indomitable', 'Fighter: Indomitable', 'When you fail a saving throw, reroll it with a bonus equal to your Fighter level. Uses increase at higher Fighter levels.', 'special', NULL, False),
    ('Fighter: Tactical Master', 'Fighter: Tactical Master', 'When you attack with a weapon whose mastery property you can use, you can replace that property with Push, Sap, or Slow for that attack.', 'special', NULL, False),
    ('Fighter: Two Extra Attacks', 'Fighter: Two Extra Attacks', 'You can attack three times instead of once whenever you take the Attack action.', 'special', NULL, False),
    ('Fighter: Studied Attacks', 'Fighter: Studied Attacks', 'When you miss a creature with an attack roll, you have Advantage on your next attack roll against that creature.', 'special', NULL, False),
    ('Fighter: Action Surge (Two Uses)', 'Fighter: Action Surge (Two Uses)', 'You can use Action Surge twice between rests, but only once per turn.', 'special', NULL, False),
    ('Fighter: Epic Boon', 'Fighter: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Fighter: Three Extra Attacks', 'Fighter: Three Extra Attacks', 'You can attack four times instead of once whenever you take the Attack action.', 'special', NULL, False),
    ('Fighter (Battle Master): Combat Superiority', 'Fighter (Battle Master): Combat Superiority', 'Learn three maneuvers fueled by four d8 Superiority Dice. Gain more maneuvers and dice at higher Fighter levels, and regain dice on Short or Long Rest.', 'special', NULL, True),
    ('Fighter (Battle Master): Student of War', 'Fighter (Battle Master): Student of War', 'Gain proficiency with one type of Artisan''s Tools and one skill from the Fighter skill list.', 'special', NULL, False),
    ('Fighter (Battle Master): Know Your Enemy', 'Fighter (Battle Master): Know Your Enemy', 'Bonus Action to learn whether a visible creature within 30 feet has Immunities, Resistances, or Vulnerabilities, and what they are.', 'special', NULL, False),
    ('Fighter (Battle Master): Improved Combat Superiority', 'Fighter (Battle Master): Improved Combat Superiority', 'Your Superiority Die becomes a d10.', 'special', NULL, False),
    ('Fighter (Battle Master): Relentless', 'Fighter (Battle Master): Relentless', 'Once per turn when you use a maneuver, you can roll 1d8 and use that result instead of expending a Superiority Die.', 'special', NULL, False),
    ('Fighter (Battle Master): Ultimate Combat Superiority', 'Fighter (Battle Master): Ultimate Combat Superiority', 'Your Superiority Die becomes a d12.', 'special', NULL, False),
    ('Fighter (Champion): Improved Critical', 'Fighter (Champion): Improved Critical', 'Your attack rolls with weapons and Unarmed Strikes score a Critical Hit on a d20 roll of 19 or 20.', 'special', NULL, False),
    ('Fighter (Champion): Remarkable Athlete', 'Fighter (Champion): Remarkable Athlete', 'Gain Advantage on Initiative rolls and Strength (Athletics) checks. After you score a Critical Hit, move up to half your Speed without provoking Opportunity Attacks.', 'special', NULL, False),
    ('Fighter (Champion): Additional Fighting Style', 'Fighter (Champion): Additional Fighting Style', 'Gain another Fighting Style feat of your choice.', 'special', NULL, False),
    ('Fighter (Champion): Heroic Warrior', 'Fighter (Champion): Heroic Warrior', 'During combat, if you start your turn without Heroic Inspiration, you can give yourself Heroic Inspiration.', 'special', NULL, False),
    ('Fighter (Champion): Superior Critical', 'Fighter (Champion): Superior Critical', 'Your attack rolls with weapons and Unarmed Strikes score a Critical Hit on a d20 roll of 18-20.', 'special', NULL, False),
    ('Fighter (Champion): Survivor Rally', 'Fighter (Champion): Survivor Rally', 'Gain Advantage on Death Saving Throws, treat 18-20 as a 20 on those saves, and regain HP at the start of your turns while Bloodied and above 0 HP.', 'special', NULL, False),
    ('Fighter (Eldritch Knight): Spellcasting (Eldritch Knight)', 'Fighter (Eldritch Knight): Spellcasting (Eldritch Knight)', 'Cast prepared Wizard spells using Intelligence. You start with two Wizard cantrips and three level 1 prepared Wizard spells, and use an Arcane Focus.', 'special', NULL, False),
    ('Fighter (Eldritch Knight): War Bond', 'Fighter (Eldritch Knight): War Bond', 'Bond with up to two weapons. You can summon a bonded weapon to your hand as a Bonus Action.', 'special', NULL, False),
    ('Fighter (Eldritch Knight): War Magic', 'Fighter (Eldritch Knight): War Magic', 'When you take the Attack action, you can replace one of your attacks with a Cantrip.', 'special', NULL, False),
    ('Fighter (Eldritch Knight): Eldritch Strike', 'Fighter (Eldritch Knight): Eldritch Strike', 'When you hit a creature with a weapon attack, it has Disadvantage on the next saving throw it makes against a spell you cast before the end of your next turn.', 'special', NULL, False),
    ('Fighter (Eldritch Knight): Arcane Charge', 'Fighter (Eldritch Knight): Arcane Charge', 'When you use your Action Surge, you can teleport up to 30ft to an unoccupied space you can see.', 'special', NULL, False),
    ('Fighter (Eldritch Knight): Improved War Magic', 'Fighter (Eldritch Knight): Improved War Magic', 'When you take the Attack action, you can replace two attacks with a level 1 or 2 Wizard spell that has a casting time of an action.', 'special', NULL, False),
    ('Fighter (Psi Warrior): Psionic Power', 'Fighter (Psi Warrior): Psionic Power', 'Gain Psionic Energy Dice that fuel Protective Field, Psionic Strike, and Telekinetic Movement. Regain one die on Short Rest and all on Long Rest.', 'special', NULL, False),
    ('Fighter (Psi Warrior): Psi-Powered Leap', 'Fighter (Psi Warrior): Psi-Powered Leap', 'Gain Psi-Powered Leap (Bonus Action flight) and Telekinetic Thrust (Push/Prone on Psionic Strike).', 'special', 'While active (until the end of this turn).', False),
    ('Fighter (Psi Warrior): Guarded Mind', 'Fighter (Psi Warrior): Guarded Mind', 'Gain resistance to Psychic damage. If Frightened or Charmed, spend a Psi die to end the effect.', 'damage_adjustment', NULL, False),
    ('Fighter (Psi Warrior): Bulwark of Force', 'Fighter (Psi Warrior): Bulwark of Force', 'Bonus Action to grant yourself and allies Half Cover for 1 minute.', 'special', 'While active (1 minute).', False),
    ('Fighter (Psi Warrior): Telekinetic Master', 'Fighter (Psi Warrior): Telekinetic Master', 'Always prepare Telekinesis and cast it without a spell slot or components using Intelligence. While concentrating on it, make one weapon attack as a Bonus Action.', 'special', NULL, False),
    ('Monk: Martial Arts', 'Monk: Martial Arts', 'While unarmed or using Monk weapons without armor or a Shield, make an Unarmed Strike as a Bonus Action, use your Martial Arts die for damage, and use Dexterity for attacks, damage, Grapple DCs, and Shove DCs.', 'special', NULL, False),
    ('Monk: Unarmored Defense', 'Monk: Unarmored Defense', 'While not wearing armor or a shield, your AC equals 10 + Dexterity + Wisdom.', 'modifier', 'Conditions: no_armor.', False),
    ('Monk: Monk''s Focus', 'Monk: Monk''s Focus', 'Gain Focus Points equal to your Monk level, refreshing on a Short or Long Rest. Spend them on Flurry of Blows, Patient Defense, Step of the Wind, and other Monk features.', 'special', NULL, False),
    ('Monk: Unarmored Movement', 'Monk: Unarmored Movement', 'Your speed increases while you are not wearing armor or a shield.', 'special', NULL, False),
    ('Monk: Uncanny Metabolism', 'Monk: Uncanny Metabolism', 'Once per Long Rest when you roll Initiative, regain all expended Focus Points and regain HP equal to your Monk level plus one roll of your Martial Arts die.', 'special', NULL, False),
    ('Monk: Deflect Attacks', 'Monk: Deflect Attacks', 'Reaction when an attack hits you and deals Bludgeoning, Piercing, or Slashing damage, reducing the damage by 1d10 + Dexterity modifier + Monk level. If reduced to 0, spend Focus to redirect it.', 'special', NULL, False),
    ('Monk: Slow Fall', 'Monk: Slow Fall', 'You can use your reaction when you fall to reduce any falling damage you take.', 'special', NULL, False),
    ('Monk: Extra Attack', 'Monk: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action on your turn.', 'special', NULL, False),
    ('Monk: Stunning Strike', 'Monk: Stunning Strike', 'Once per turn when you hit with a Monk weapon or Unarmed Strike, spend 1 Focus Point to force a Constitution save. On a failure, the target is Stunned until your next turn; on a success, its Speed is halved and the next attack against it has Advantage.', 'special', NULL, False),
    ('Monk: Empowered Strikes', 'Monk: Empowered Strikes', 'Whenever you deal damage with an Unarmed Strike, it can deal Force damage or its normal damage type.', 'special', NULL, False),
    ('Monk: Evasion', 'Monk: Evasion', 'You can nimbly dodge out of the way of certain area effects.', 'special', NULL, False),
    ('Monk: Acrobatic Movement', 'Monk: Acrobatic Movement', 'You can move along vertical surfaces and across liquids on your turn without falling.', 'special', NULL, False),
    ('Monk: Heightened Focus', 'Monk: Heightened Focus', 'Improve your core Focus options: Flurry of Blows makes three strikes, Patient Defense grants Temporary Hit Points, and Step of the Wind can move a nearby willing creature with you.', 'special', NULL, False),
    ('Monk: Self-Restoration', 'Monk: Self-Restoration', 'At the end of each of your turns, remove Charmed, Frightened, or Poisoned from yourself. Forgoing food and drink no longer gives you Exhaustion.', 'special', NULL, False),
    ('Monk: Deflect Energy', 'Monk: Deflect Energy', 'You can use your Deflect Attacks feature against any damage type, not just Physical.', 'special', NULL, False),
    ('Monk: Disciplined Survivor', 'Monk: Disciplined Survivor', 'Gain proficiency in all saving throws. If you fail a save, spend Focus to reroll.', 'special', NULL, False),
    ('Monk: Perfect Focus', 'Monk: Perfect Focus', 'When you roll Initiative and do not use Uncanny Metabolism, regain expended Focus Points until you have 4 if you had 3 or fewer.', 'special', NULL, False),
    ('Monk: Superior Defense', 'Monk: Superior Defense', 'At the start of your turn, spend 3 Focus Points to gain Resistance to all damage except Force for 1 minute or until Incapacitated.', 'special', 'While active (1 minute).', False),
    ('Monk: Epic Boon', 'Monk: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Monk: Body and Mind', 'Monk: Body and Mind', 'Your Dexterity and Wisdom scores increase by 4, up to a maximum of 25.', 'special', NULL, False),
    ('Monk (Warrior of Mercy): Hand of Harm', 'Monk (Warrior of Mercy): Hand of Harm', 'Once per turn when you hit with an Unarmed Strike and deal damage, spend 1 Focus Point to deal extra Necrotic damage equal to one Martial Arts die plus Wisdom.', 'special', NULL, False),
    ('Monk (Warrior of Mercy): Hand of Healing', 'Monk (Warrior of Mercy): Hand of Healing', 'Magic Action to spend 1 Focus Point and touch a creature, restoring HP equal to one Martial Arts die plus Wisdom. When using Flurry of Blows, replace one strike with this healing for no Focus cost.', 'special', NULL, False),
    ('Monk (Warrior of Mercy): Implements of Mercy', 'Monk (Warrior of Mercy): Implements of Mercy', 'Gain proficiency in Insight, Medicine, and Herbalism Kit. You gain a special mask.', 'special', NULL, False),
    ('Monk (Warrior of Mercy): Physician''s Touch', 'Monk (Warrior of Mercy): Physician''s Touch', 'Hand of Healing ends Blinded, Deafened, Paralyzed, Poisoned, or Stunned. Hand of Harm Poisons target.', 'special', NULL, False),
    ('Monk (Warrior of Mercy): Flurry of Healing and Harm', 'Monk (Warrior of Mercy): Flurry of Healing and Harm', 'When using Flurry of Blows, replace any strikes with Hand of Healing for no Focus cost and use Hand of Harm once without spending Focus. Uses equal Wisdom modifier per Long Rest.', 'special', NULL, False),
    ('Monk (Warrior of Mercy): Hand of Ultimate Mercy', 'Monk (Warrior of Mercy): Hand of Ultimate Mercy', 'Magic Action to touch a creature that died within 24 hours and spend 5 Focus Points, returning it to life with 4d10 + Wisdom HP and removing certain conditions. Once per Long Rest.', 'special', NULL, False),
    ('Monk (Warrior of Shadow): Shadow Arts', 'Monk (Warrior of Shadow): Shadow Arts', 'Gain Darkvision, learn Minor Illusion using Wisdom, and spend 1 Focus Point to cast Darkness without components. You can see through this Darkness and move it at the start of your turns.', 'special', NULL, False),
    ('Monk (Warrior of Shadow): Shadow Step', 'Monk (Warrior of Shadow): Shadow Step', 'Bonus Action to teleport up to 60ft between areas of dim light or darkness. Gain Advantage on next attack.', 'special', NULL, False),
    ('Monk (Warrior of Shadow): Improved Shadow Step', 'Monk (Warrior of Shadow): Improved Shadow Step', 'When using Shadow Step, spend 1 Focus Point to ignore the dim light or darkness requirement for that teleport and make an Unarmed Strike as part of the Bonus Action.', 'special', NULL, False),
    ('Monk (Warrior of Shadow): Cloak of Shadows', 'Monk (Warrior of Shadow): Cloak of Shadows', 'Magic Action while in dim light or darkness to spend 3 Focus Points and become shrouded for 1 minute, gaining Invisibility, partial incorporeality, and free Flurry of Blows.', 'special', 'While active (1 minute).', False),
    ('Monk (Warrior of the Elements): Elemental Attunement', 'Monk (Warrior of the Elements): Elemental Attunement', 'At the start of your turn, spend 1 Focus Point to imbue yourself for 10 minutes. Your Unarmed Strikes gain 10-foot extra reach, can deal Acid, Cold, Fire, Lightning, or Thunder damage, and can pull or push targets.', 'special', 'While active (10 minutes).', False),
    ('Monk (Warrior of the Elements): Manipulate Elements', 'Monk (Warrior of the Elements): Manipulate Elements', 'You know the Elementalism spell, using Wisdom as your spellcasting ability.', 'special', NULL, False),
    ('Monk (Warrior of the Elements): Elemental Burst', 'Monk (Warrior of the Elements): Elemental Burst', 'Magic Action to spend 2 Focus Points and create a 20-foot-radius sphere within 120 feet, dealing three Martial Arts dice of Acid, Cold, Fire, Lightning, or Thunder damage on a failed Dexterity save.', 'special', NULL, False),
    ('Monk (Warrior of the Elements): Stride of the Elements', 'Monk (Warrior of the Elements): Stride of the Elements', 'While Elemental Attunement is active, you gain a Fly Speed and Swim Speed equal to your Speed.', 'special', NULL, False),
    ('Monk (Warrior of the Elements): Elemental Epitome', 'Monk (Warrior of the Elements): Elemental Epitome', 'While Elemental Attunement is active, gain changeable elemental Resistance, damage nearby creatures during Step of the Wind, and add one Martial Arts die of elemental damage once per turn.', 'special', NULL, False),
    ('Monk (Warrior of the Open Hand): Open Hand Technique', 'Monk (Warrior of the Open Hand): Open Hand Technique', 'When you hit with an attack from Flurry of Blows, impose Addle to prevent Opportunity Attacks, Push up to 15 feet on a failed Strength save, or Topple on a failed Dexterity save.', 'special', NULL, False),
    ('Monk (Warrior of the Open Hand): Wholeness of Body', 'Monk (Warrior of the Open Hand): Wholeness of Body', 'Bonus Action to regain HP equal to one Martial Arts die plus Wisdom modifier. Uses equal Wisdom modifier per Long Rest.', 'special', NULL, False),
    ('Monk (Warrior of the Open Hand): Fleet Step', 'Monk (Warrior of the Open Hand): Fleet Step', 'When you take a Bonus Action other than Step of the Wind, you can also use Step of the Wind immediately after that Bonus Action.', 'special', NULL, False),
    ('Monk (Warrior of the Open Hand): Quivering Palm', 'Monk (Warrior of the Open Hand): Quivering Palm', 'When you hit with an Unarmed Strike, spend 4 Focus Points to set vibrations lasting days equal to your Monk level. End them later to force a Constitution save for 10d12 Force damage, or half on success.', 'special', NULL, False),
    ('Paladin: Lay On Hands', 'Paladin: Lay On Hands', 'Bonus Action to touch a creature and restore HP from a pool equal to 5 times your Paladin level. Spend 5 points from the pool to remove Poisoned instead of restoring HP.', 'special', NULL, False),
    ('Paladin: Spellcasting', 'Paladin: Spellcasting', 'Cast prepared Paladin spells using Charisma. You start with two level 1 prepared Paladin spells, and use a Holy Symbol as a spellcasting focus.', 'special', NULL, False),
    ('Paladin: Weapon Mastery', 'Paladin: Weapon Mastery', 'Use mastery properties for two weapons with which you have proficiency, changing your choices after each Long Rest.', 'special', NULL, False),
    ('Paladin: Fighting Style', 'Paladin: Fighting Style', 'Gain a Fighting Style feat of your choice, or choose Blessed Warrior to learn two Cleric cantrips using Charisma.', 'special', NULL, True),
    ('Paladin: Paladin''s Smite', 'Paladin: Paladin''s Smite', 'Always prepare Divine Smite. You can cast it once without expending a spell slot, regaining that free casting after a Long Rest.', 'special', NULL, False),
    ('Paladin: Channel Divinity', 'Paladin: Channel Divinity', 'Channel divine energy to fuel Divine Sense and your oath''s Channel Divinity options. Regain one expended use on a Short Rest and all uses on a Long Rest.', 'special', NULL, False),
    ('Paladin: Divine Sense', 'Paladin: Divine Sense', 'Bonus Action using Channel Divinity to detect Celestials, Fiends, Undead, and consecrated or desecrated places or objects within 60 feet for 10 minutes.', 'special', 'While active (10 minutes).', False),
    ('Paladin: Extra Attack', 'Paladin: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action.', 'special', NULL, False),
    ('Paladin: Faithful Steed', 'Paladin: Faithful Steed', 'Always prepare Find Steed. You can cast it once without expending a spell slot, regaining that free casting after a Long Rest.', 'special', NULL, False),
    ('Paladin: Aura of Protection', 'Paladin: Aura of Protection', 'You and allies in your 10-foot Aura of Protection gain a bonus to saving throws equal to your Charisma modifier, minimum +1. The aura is inactive while you are Incapacitated.', 'special', NULL, False),
    ('Paladin: Abjure Foes', 'Paladin: Abjure Foes', 'Magic Action using Channel Divinity to target creatures up to your Charisma modifier within 60 feet. On a failed Wisdom save, each target is Frightened and limited to movement, an action, or a Bonus Action each turn until it takes damage.', 'special', 'While active (1 minute or until damaged).', False),
    ('Paladin: Aura of Courage', 'Paladin: Aura of Courage', 'You and allies have Immunity to Frightened while in your Aura of Protection.', 'special', NULL, False),
    ('Paladin: Radiant Strikes', 'Paladin: Radiant Strikes', 'When you hit with a Melee weapon or Unarmed Strike, the target takes an extra 1d8 Radiant damage.', 'special', NULL, False),
    ('Paladin: Restoring Touch', 'Paladin: Restoring Touch', 'When you use Lay On Hands, spend 5 points from the healing pool per condition to remove Blinded, Charmed, Deafened, Frightened, Paralyzed, or Stunned.', 'special', NULL, False),
    ('Paladin: Aura Expansion', 'Paladin: Aura Expansion', 'The range of your Auras increases to 30ft.', 'special', NULL, False),
    ('Paladin: Epic Boon', 'Paladin: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Paladin (Oath of Devotion): Oath of Devotion Spells', 'Paladin (Oath of Devotion): Oath of Devotion Spells', 'Always prepare Protection from Evil and Good and Shield of Faith; later add Aid, Zone of Truth, Beacon of Hope, Dispel Magic, Freedom of Movement, Guardian of Faith, Commune, and Flame Strike.', 'special', NULL, False),
    ('Paladin (Oath of Devotion): Sacred Weapon', 'Paladin (Oath of Devotion): Sacred Weapon', 'When you take the Attack action, expend Channel Divinity to imbue one held Melee weapon for 10 minutes. Add Charisma to attack rolls, deal normal or Radiant damage, and emit bright holy light.', 'special', 'While active (10 minutes).', False),
    ('Paladin (Oath of Devotion): Aura of Devotion', 'Paladin (Oath of Devotion): Aura of Devotion', 'You and allies have Immunity to Charmed while in your Aura of Protection.', 'special', NULL, False),
    ('Paladin (Oath of Devotion): Smite of Protection', 'Paladin (Oath of Devotion): Smite of Protection', 'Whenever you cast Divine Smite, you and allies have Half Cover while in your Aura of Protection until the start of your next turn.', 'special', NULL, False),
    ('Paladin (Oath of Devotion): Holy Nimbus', 'Paladin (Oath of Devotion): Holy Nimbus', 'Bonus Action to empower your Aura of Protection for 10 minutes with sunlight, Radiant damage to enemies that start there, and Advantage on saves forced by Fiends or Undead.', 'special', 'While active (10 minutes).', False),
    ('Paladin (Oath of Glory): Inspiring Smite', 'Paladin (Oath of Glory): Inspiring Smite', 'Immediately after casting Divine Smite, expend Channel Divinity to distribute 2d8 + Paladin level Temporary Hit Points among creatures within 30 feet.', 'special', NULL, False),
    ('Paladin (Oath of Glory): Oath of Glory Spells', 'Paladin (Oath of Glory): Oath of Glory Spells', 'Always prepare Guiding Bolt and Heroism; later add Enhance Ability, Magic Weapon, Haste, Protection from Energy, Compulsion, Freedom of Movement, Legend Lore, and Yolande''s Regal Presence.', 'special', NULL, False),
    ('Paladin (Oath of Glory): Peerless Athlete', 'Paladin (Oath of Glory): Peerless Athlete', 'Bonus Action using Channel Divinity to gain Advantage on Athletics and Acrobatics checks for 1 hour, and increase long and high jumps by 10 feet.', 'special', 'While active (1 hour).', False),
    ('Paladin (Oath of Glory): Aura of Alacrity', 'Paladin (Oath of Glory): Aura of Alacrity', 'Your Speed increases by 10 feet. Allies gain +10 feet of Speed until the end of their next turn when they enter or start in your Aura of Protection.', 'modifier', NULL, False),
    ('Paladin (Oath of Glory): Glorious Defense', 'Paladin (Oath of Glory): Glorious Defense', 'Reaction to add your CHA modifier to the AC of you or an ally, potentially causing a miss; then counterattack.', 'special', NULL, False),
    ('Paladin (Oath of Glory): Living Legend', 'Paladin (Oath of Glory): Living Legend', 'Bonus Action to become a living legend for 10 minutes, gaining Advantage on Charisma checks, a saving throw reroll Reaction, and one weapon miss turned into a hit each turn.', 'special', 'While active (10 minutes).', False),
    ('Paladin (Oath of the Ancients): Nature''s Wrath', 'Paladin (Oath of the Ancients): Nature''s Wrath', 'Magic Action using Channel Divinity to conjure spectral vines. Chosen creatures within 15 feet must make a Strength save or be Restrained for 1 minute, repeating the save at the end of each turn.', 'special', 'While active (1 minute).', False),
    ('Paladin (Oath of the Ancients): Oath of the Ancients Spells', 'Paladin (Oath of the Ancients): Oath of the Ancients Spells', 'Always prepare Ensnaring Strike and Speak with Animals; later add Misty Step, Moonbeam, Plant Growth, Protection from Energy, Ice Storm, Stoneskin, Commune with Nature, and Tree Stride.', 'special', NULL, False),
    ('Paladin (Oath of the Ancients): Aura of Warding', 'Paladin (Oath of the Ancients): Aura of Warding', 'You and allies have Resistance to Necrotic, Psychic, and Radiant damage while in your Aura of Protection.', 'damage_adjustment', NULL, False),
    ('Paladin (Oath of the Ancients): Undying Sentinel', 'Paladin (Oath of the Ancients): Undying Sentinel', 'When you are reduced to 0 HP and not killed outright, drop to 1 HP and regain HP equal to three times your Paladin level. You also cease visibly aging and cannot be aged magically.', 'special', NULL, False),
    ('Paladin (Oath of the Ancients): Elder Champion', 'Paladin (Oath of the Ancients): Elder Champion', 'Bonus Action to empower your Aura of Protection for 1 minute, giving enemies Disadvantage against your spells and Channel Divinity, restoring 10 HP each turn, and letting you cast action spells as Bonus Actions.', 'special', 'While active (1 minute).', False),
    ('Paladin (Oath of Vengeance): Oath of Vengeance Spells', 'Paladin (Oath of Vengeance): Oath of Vengeance Spells', 'Always prepare Bane and Hunter''s Mark; later add Hold Person, Misty Step, Haste, Protection from Energy, Banishment, Dimension Door, Hold Monster, and Scrying.', 'special', NULL, False),
    ('Paladin (Oath of Vengeance): Vow of Enmity', 'Paladin (Oath of Vengeance): Vow of Enmity', 'When you take the Attack action, expend Channel Divinity to vow against a visible creature within 30 feet. Gain Advantage on attacks against it for 1 minute, and transfer the vow if it drops to 0 HP.', 'special', 'While active (1 minute).', False),
    ('Paladin (Oath of Vengeance): Relentless Avenger', 'Paladin (Oath of Vengeance): Relentless Avenger', 'When you hit a creature with an Opportunity Attack, reduce its Speed to 0 until the end of the turn and move up to half your Speed without provoking Opportunity Attacks.', 'special', NULL, False),
    ('Paladin (Oath of Vengeance): Soul of Vengeance', 'Paladin (Oath of Vengeance): Soul of Vengeance', 'Immediately after the target of your Vow of Enmity hits or misses with an attack roll, use your Reaction to make a melee attack against it if it is within range.', 'special', NULL, False),
    ('Paladin (Oath of Vengeance): Avenging Angel', 'Paladin (Oath of Vengeance): Avenging Angel', 'Bonus Action to gain spectral wings, a 60-foot Fly Speed with hover, and an Aura of Protection that can Frighten enemies and grant Advantage on attacks against them.', 'special', 'While active (10 minutes).', False),
    ('Ranger: Favored Enemy', 'Ranger: Favored Enemy', 'Always prepare Hunter''s Mark. You can cast it without a spell slot twice per Long Rest, gaining more free castings at higher Ranger levels.', 'special', 'While active (Concentration, up to 1 hour).', False),
    ('Ranger: Spellcasting', 'Ranger: Spellcasting', 'Cast prepared Ranger spells using Wisdom. You start with two level 1 prepared Ranger spells, and use a Druidic Focus as a spellcasting focus.', 'special', NULL, False),
    ('Ranger: Weapon Mastery', 'Ranger: Weapon Mastery', 'Use mastery properties for two weapons with which you have proficiency, changing your choices after each Long Rest.', 'special', NULL, False),
    ('Ranger: Deft Explorer', 'Ranger: Deft Explorer', 'Gain Expertise in one of your Ranger skill proficiencies and learn two languages of your choice.', 'special', NULL, False),
    ('Ranger: Fighting Style', 'Ranger: Fighting Style', 'Gain a Fighting Style feat of your choice, or choose Druidic Warrior to learn two Druid cantrips using Wisdom.', 'special', NULL, True),
    ('Ranger: Extra Attack', 'Ranger: Extra Attack', 'You can attack twice instead of once.', 'special', NULL, False),
    ('Ranger: Roving', 'Ranger: Roving', 'Your Speed increases by 10 feet while you are not wearing Heavy armor, and you gain Climb and Swim Speeds equal to your Speed.', 'modifier', NULL, False),
    ('Ranger: Expertise', 'Ranger: Expertise', 'Choose two more skill proficiencies with which you lack Expertise. You gain Expertise in those skills.', 'special', NULL, False),
    ('Ranger: Tireless', 'Ranger: Tireless', 'Magic Action to gain Temporary Hit Points equal to 1d8 + Wisdom modifier a limited number of times per Long Rest. Your Exhaustion level also decreases by 1 whenever you finish a Short Rest.', 'special', NULL, False),
    ('Ranger: Relentless Hunter', 'Ranger: Relentless Hunter', 'Taking damage cannot break your Concentration on Hunter''s Mark.', 'special', NULL, False),
    ('Ranger: Nature''s Veil', 'Ranger: Nature''s Veil', 'Bonus Action to give yourself the Invisible condition until the end of your next turn. Uses equal Wisdom modifier per Long Rest.', 'special', 'While active (until the end of your next turn).', False),
    ('Ranger: Precise Hunter', 'Ranger: Precise Hunter', 'You have Advantage on attack rolls against the creature currently marked by your Hunter''s Mark.', 'special', NULL, False),
    ('Ranger: Feral Senses', 'Ranger: Feral Senses', 'Gain Blindsight with a range of 30 feet.', 'special', NULL, False),
    ('Ranger: Epic Boon', 'Ranger: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Ranger: Foe Slayer', 'Ranger: Foe Slayer', 'The damage die of your Hunter''s Mark becomes a d10 instead of a d6.', 'special', NULL, False),
    ('Ranger (Beast Master): Primal Companion', 'Ranger (Beast Master): Primal Companion', 'Magically summon a Beast of the Land, Sea, or Sky. It acts during your turn, obeys your commands, and can be commanded with a Bonus Action or by sacrificing one of your attacks.', 'special', NULL, False),
    ('Ranger (Beast Master): Exceptional Training', 'Ranger (Beast Master): Exceptional Training', 'When you command your Primal Companion with a Bonus Action, also command it to Dash, Disengage, Dodge, or Help as its Bonus Action. Its attacks can deal Force damage.', 'special', NULL, False),
    ('Ranger (Beast Master): Bestial Fury', 'Ranger (Beast Master): Bestial Fury', 'When you command your Primal Companion to take Beast''s Strike, it strikes twice. The first time each turn it hits your Hunter''s Mark target, it deals extra Force damage equal to the spell''s bonus damage.', 'special', NULL, False),
    ('Ranger (Beast Master): Share Spells', 'Ranger (Beast Master): Share Spells', 'When you cast a spell targeting yourself, you can also affect your Primal Companion if it is within 30 feet.', 'special', NULL, False),
    ('Ranger (Fey Wanderer): Dreadful Strikes', 'Ranger (Fey Wanderer): Dreadful Strikes', 'Once per turn when you hit a creature with a weapon, deal extra Psychic damage. The damage increases at Ranger level 11.', 'special', NULL, False),
    ('Ranger (Fey Wanderer): Fey Wanderer Spells', 'Ranger (Fey Wanderer): Fey Wanderer Spells', 'Always prepare Charm Person; later add Misty Step, Summon Fey, Dimension Door, and Mislead.', 'special', NULL, False),
    ('Ranger (Fey Wanderer): Otherworldly Glamour', 'Ranger (Fey Wanderer): Otherworldly Glamour', 'Add your Wisdom modifier to Charisma checks, minimum +1, and gain proficiency in Deception, Performance, or Persuasion.', 'special', NULL, True),
    ('Ranger (Fey Wanderer): Beguiling Twist', 'Ranger (Fey Wanderer): Beguiling Twist', 'Gain Advantage on saves to avoid or end Charmed or Frightened. When a visible creature succeeds on such a save, use a Reaction to force another visible creature within 120 feet to save or become Charmed or Frightened.', 'special', NULL, False),
    ('Ranger (Fey Wanderer): Fey Reinforcements', 'Ranger (Fey Wanderer): Fey Reinforcements', 'Cast Summon Fey without a Material component, and once per Long Rest without a spell slot. When casting it, you can remove Concentration for that casting and reduce its duration to 1 minute.', 'special', NULL, False),
    ('Ranger (Fey Wanderer): Misty Wanderer', 'Ranger (Fey Wanderer): Misty Wanderer', 'Cast Misty Step without a spell slot a number of times equal to your Wisdom modifier per Long Rest. Whenever you cast it, bring one willing nearby creature with you.', 'special', NULL, False),
    ('Ranger (Gloom Stalker): Dread Ambusher', 'Ranger (Gloom Stalker): Dread Ambusher', 'Add Wisdom to Initiative, gain +10 feet of Speed on your first turn of each combat, and use Dreadful Strike to deal Psychic damage a limited number of times per Long Rest.', 'special', NULL, False),
    ('Ranger (Gloom Stalker): Gloom Stalker Spells', 'Ranger (Gloom Stalker): Gloom Stalker Spells', 'Always prepare Disguise Self; later add Rope Trick, Fear, Greater Invisibility, and Seeming.', 'special', NULL, False),
    ('Ranger (Gloom Stalker): Umbral Sight', 'Ranger (Gloom Stalker): Umbral Sight', 'Gain Darkvision 60 feet, or increase existing Darkvision by 60 feet. While entirely in Darkness, you are Invisible to creatures relying on Darkvision to see you.', 'special', NULL, False),
    ('Ranger (Gloom Stalker): Iron Mind', 'Ranger (Gloom Stalker): Iron Mind', 'Gain proficiency in Wisdom saving throws. If you already have it, gain proficiency in Intelligence or Charisma saving throws instead.', 'special', NULL, False),
    ('Ranger (Gloom Stalker): Stalker''s Flurry', 'Ranger (Gloom Stalker): Stalker''s Flurry', 'Your Dreadful Strike becomes 2d8, and when you use it you can either attack a second nearby creature or force the target and nearby creatures to save or become Frightened.', 'special', NULL, False),
    ('Ranger (Gloom Stalker): Shadowy Dodge', 'Ranger (Gloom Stalker): Shadowy Dodge', 'Reaction when a creature makes an attack roll against you to impose Disadvantage on the roll, then teleport up to 30 feet whether the attack hits or misses.', 'special', NULL, False),
    ('Ranger (Hunter): Hunter''s Lore', 'Ranger (Hunter): Hunter''s Lore', 'While a creature is marked by your Hunter''s Mark, you know whether it has Immunities, Resistances, or Vulnerabilities, and what they are.', 'special', NULL, False),
    ('Ranger (Hunter): Hunter''s Prey', 'Ranger (Hunter): Hunter''s Prey', 'Choose Colossus Slayer for extra damage against wounded foes or Horde Breaker for an extra attack against a nearby different creature. You can swap the option after a Short or Long Rest.', 'special', 'While active (until changed after a Short or Long Rest).', False),
    ('Ranger (Hunter): Defensive Tactics', 'Ranger (Hunter): Defensive Tactics', 'Choose Escape the Horde to impose Disadvantage on Opportunity Attacks against you or Multiattack Defense to impose Disadvantage on later attacks from a creature that hit you this turn. You can swap the option after a Short or Long Rest.', 'special', 'While active (until changed after a Short or Long Rest).', False),
    ('Ranger (Hunter): Superior Hunter''s Prey', 'Ranger (Hunter): Superior Hunter''s Prey', 'Once per turn when you damage a creature marked by Hunter''s Mark, also deal that spell''s extra damage to a different visible creature within 30 feet of the first.', 'special', NULL, False),
    ('Ranger (Hunter): Superior Hunter''s Defense', 'Ranger (Hunter): Superior Hunter''s Defense', 'When you take damage, use a Reaction to gain Resistance to that damage and any other damage of the same type until the end of the current turn.', 'special', NULL, False),
    ('Rogue: Expertise', 'Rogue: Expertise', 'Choose two more of your skill proficiencies to gain Expertise.', 'special', NULL, False),
    ('Rogue: Sneak Attack', 'Rogue: Sneak Attack', 'Once per turn, you can deal extra damage to one creature you hit with an attack roll if the attack uses a Finesse or Ranged weapon and you have Advantage on the attack roll. You do not need Advantage if at least one of your allies is within 5 feet of the target, the ally does not have the Incapacitated condition, and you do not have Disadvantage on the attack roll.', 'special', NULL, False),
    ('Rogue: Thieves'' Cant', 'Rogue: Thieves'' Cant', 'You know Thieves'' Cant and one additional language of your choice.', 'special', NULL, False),
    ('Rogue: Weapon Mastery', 'Rogue: Weapon Mastery', 'Your training with weapons allows you to use the mastery properties of two weapons with which you have proficiency. Whenever you finish a Long Rest, you can change the kinds of weapons you chose.', 'special', NULL, False),
    ('Rogue: Cunning Action', 'Rogue: Cunning Action', 'Your quick thinking and agility allow you to move and act quickly. On your turn, you can take the Dash, Disengage, or Hide action as a Bonus Action.', 'special', NULL, False),
    ('Rogue: Steady Aim', 'Rogue: Steady Aim', 'As a Bonus Action, you give yourself Advantage on your next attack roll on the current turn. You can use this only if you have not moved during this turn, and after you use it, your Speed is 0 until the end of the current turn.', 'special', 'While active (until the end of this turn). Conditions: noMovementThisTurn.', False),
    ('Rogue: Cunning Strike', 'Rogue: Cunning Strike', 'You have developed cunning ways to use your Sneak Attack. When you deal Sneak Attack damage, you can forgo some of the extra dice to cause one Cunning Strike effect. Poison. Cost: 1d6. The target must succeed on a Constitution saving throw or have the Poisoned condition for 1 minute. Trip. Cost: 1d6. If the target is Large or smaller, it must succeed on a Dexterity saving throw or have the Prone condition. Withdraw. Cost: 1d6. Immediately after the attack, you move up to half your Speed without provoking Opportunity Attacks.', 'special', NULL, False),
    ('Rogue: Uncanny Dodge', 'Rogue: Uncanny Dodge', 'When an attacker that you can see hits you with an attack roll, you can take a Reaction to halve the attack damage against you.', 'special', NULL, False),
    ('Rogue: Evasion', 'Rogue: Evasion', 'When you are subjected to an effect that allows you to make a Dexterity saving throw to take only half damage, you instead take no damage if you succeed on the saving throw and only half damage if you fail. You cannot use this feature if you have the Incapacitated condition.', 'special', NULL, False),
    ('Rogue: Reliable Talent', 'Rogue: Reliable Talent', 'Whenever you make an ability check using one of your skill or tool proficiencies, treat a d20 roll of 9 or lower as a 10.', 'special', NULL, False),
    ('Rogue: Improved Cunning Strike', 'Rogue: Improved Cunning Strike', 'You can use up to two Cunning Strike effects when you deal Sneak Attack damage, paying the die cost for each effect.', 'special', NULL, False),
    ('Rogue: Devious Strikes', 'Rogue: Devious Strikes', 'You have practiced new ways to use your Cunning Strike. Daze. Cost: 2d6. The target must succeed on a Constitution saving throw or on its next turn it can do only one of the following: move or take an action or Bonus Action. Knock Out. Cost: 6d6. The target must succeed on a Constitution saving throw or have the Unconscious condition for 1 minute. Obscure. Cost: 3d6. The target must succeed on a Dexterity saving throw or have the Blinded condition until the end of its next turn.', 'special', NULL, False),
    ('Rogue: Slippery Mind', 'Rogue: Slippery Mind', 'You gain proficiency in Wisdom and Charisma saving throws.', 'special', NULL, False),
    ('Rogue: Elusive', 'Rogue: Elusive', 'No attack roll has Advantage against you while you do not have the Incapacitated condition.', 'special', NULL, False),
    ('Rogue: Epic Boon', 'Rogue: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Rogue: Stroke of Luck', 'Rogue: Stroke of Luck', 'If you fail a D20 Test, you can turn the roll into a 20. Once you use this feature, you cannot use it again until you finish a Short or Long Rest.', 'special', NULL, False),
    ('Rogue (Arcane Trickster): Mage Hand Legerdemain', 'Rogue (Arcane Trickster): Mage Hand Legerdemain', 'When you cast Mage Hand, you can cast and control it as a Bonus Action, make the spectral hand Invisible, and use it to make Sleight of Hand checks.', 'special', NULL, False),
    ('Rogue (Arcane Trickster): Spellcasting', 'Rogue (Arcane Trickster): Spellcasting', 'You can cast prepared Wizard spells using Intelligence as your spellcasting ability. You know Mage Hand and two other Wizard cantrips, prepare Wizard spells, and can use an Arcane Focus.', 'special', NULL, False),
    ('Rogue (Arcane Trickster): Magical Ambush', 'Rogue (Arcane Trickster): Magical Ambush', 'If you have the Invisible condition when you cast a spell on a creature, that creature has Disadvantage on saving throws against the spell on the same turn.', 'special', NULL, False),
    ('Rogue (Arcane Trickster): Versatile Trickster', 'Rogue (Arcane Trickster): Versatile Trickster', 'When you use the Trip option of Cunning Strike on a creature, you can also use Trip on another creature within 5 feet of your Mage Hand.', 'special', NULL, False),
    ('Rogue (Arcane Trickster): Spell Thief', 'Rogue (Arcane Trickster): Spell Thief', 'As a Reaction after a creature casts a spell that targets you or includes you in its area, force an Intelligence saving throw. On a failed save, the spell has no effect on you and you can temporarily steal it if it is a spell level you can cast.', 'special', NULL, False),
    ('Rogue (Assassin): Assassin''s Tools', 'Rogue (Assassin): Assassin''s Tools', 'You gain a Disguise Kit and a Poisoner''s Kit, and you gain proficiency with both.', 'special', NULL, False),
    ('Rogue (Assassin): Assassinate', 'Rogue (Assassin): Assassinate', 'You have Advantage on Initiative rolls. During the first round of combat, you have Advantage on attack rolls against any creature that has not taken a turn, and your Sneak Attack deals extra damage equal to your Rogue level.', 'special', NULL, False),
    ('Rogue (Assassin): Infiltration Expertise', 'Rogue (Assassin): Infiltration Expertise', 'You can mimic another person''s speech, handwriting, or both after studying them for at least 1 hour. Your Speed is no longer reduced to 0 by Steady Aim.', 'special', NULL, False),
    ('Rogue (Assassin): Envenom Weapons', 'Rogue (Assassin): Envenom Weapons', 'When you use the Poison option of Cunning Strike, the target also takes 2d6 Poison damage whenever it fails the saving throw, and the damage ignores Poison Resistance.', 'special', NULL, False),
    ('Rogue (Assassin): Death Strike', 'Rogue (Assassin): Death Strike', 'When you hit with Sneak Attack during the first round of combat, the target must succeed on a Constitution saving throw or the attack''s damage is doubled.', 'special', NULL, False),
    ('Rogue (Soulknife): Psionic Power', 'Rogue (Soulknife): Psionic Power', 'You harbor a wellspring of psionic energy represented by Psionic Energy Dice. You can expend these dice to fuel Psi-Bolstered Knack and Psychic Whispers. You regain one expended die when you finish a Short Rest and all expended dice when you finish a Long Rest.', 'special', NULL, False),
    ('Rogue (Soulknife): Psychic Blades', 'Rogue (Soulknife): Psychic Blades', 'When you take the Attack action or make an Opportunity Attack, you can manifest a Psychic Blade with the Finesse and Thrown properties and the Vex mastery. After attacking with the blade on your turn, you can make a second Psychic Blade attack as a Bonus Action if your other hand is free.', 'special', NULL, False),
    ('Rogue (Soulknife): Soul Blades', 'Rogue (Soulknife): Soul Blades', 'You can spend Psionic Energy Dice to teleport with Psychic Teleportation or improve missed Psychic Blade attacks with Homing Strikes.', 'special', NULL, False),
    ('Rogue (Soulknife): Psychic Veil', 'Rogue (Soulknife): Psychic Veil', 'As a Magic action, you gain the Invisible condition for 1 hour or until you dismiss the effect, deal damage, or force a creature to make a saving throw. Once you use this feature, you cannot use it again until you finish a Long Rest unless you expend a Psionic Energy Die.', 'special', 'While active (1 hour).', False),
    ('Rogue (Soulknife): Rend Mind', 'Rogue (Soulknife): Rend Mind', 'When your Psychic Blades deal Sneak Attack damage, you can force the target to make a Wisdom saving throw. On a failed save, the target has the Stunned condition for 1 minute. Once you use this feature, you cannot use it again until you finish a Long Rest unless you expend three Psionic Energy Dice.', 'special', NULL, False),
    ('Rogue (Thief): Fast Hands', 'Rogue (Thief): Fast Hands', 'As a Bonus Action, you can make a Dexterity (Sleight of Hand) check to pick a lock, disarm a trap, or pick a pocket, or you can take the Utilize action or the Magic action to use a magic item.', 'special', NULL, False),
    ('Rogue (Thief): Second-Story Work', 'Rogue (Thief): Second-Story Work', 'You gain a Climb Speed equal to your Speed, and you can use Dexterity instead of Strength to determine your jump distance.', 'special', NULL, False),
    ('Rogue (Thief): Supreme Sneak', 'Rogue (Thief): Supreme Sneak', 'You gain the Stealth Attack option for Cunning Strike, allowing an attack from hiding to avoid ending the Invisible condition if you end the turn behind strong cover.', 'special', NULL, False),
    ('Rogue (Thief): Use Magic Device', 'Rogue (Thief): Use Magic Device', 'You can attune to up to four magic items, sometimes avoid spending item charges, and use any Spell Scroll with Intelligence as your spellcasting ability.', 'special', NULL, False),
    ('Rogue (Thief): Thief''s Reflexes', 'Rogue (Thief): Thief''s Reflexes', 'You can take two turns during the first round of any combat.', 'special', NULL, False),
    ('Sorcerer: Innate Sorcery', 'Sorcerer: Innate Sorcery', 'Bonus Action to awaken your innate magic for 1 minute. Your Sorcerer spell save DC increases by 1, and you have Advantage on attack rolls of Sorcerer spells.', 'special', 'While active (1 minute).', False),
    ('Sorcerer: Spellcasting', 'Sorcerer: Spellcasting', 'Cast prepared Sorcerer spells using Charisma. You start with four Sorcerer cantrips and two level 1 prepared spells, and use an Arcane Focus as a spellcasting focus.', 'special', NULL, False),
    ('Sorcerer: Font of Magic', 'Sorcerer: Font of Magic', 'Gain Sorcery Points equal to your Sorcerer level. Use them to create spell slots, convert slots into Sorcery Points, and fuel Sorcerer features.', 'special', NULL, False),
    ('Sorcerer: Metamagic', 'Sorcerer: Metamagic', 'Learn two more Metamagic options.', 'special', NULL, False),
    ('Sorcerer: Sorcerous Restoration', 'Sorcerer: Sorcerous Restoration', 'Once per Long Rest when you finish a Short Rest, regain expended Sorcery Points up to half your Sorcerer level, rounded down.', 'special', NULL, False),
    ('Sorcerer: Sorcery Incarnate', 'Sorcerer: Sorcery Incarnate', 'If you have no Innate Sorcery uses left, spend 2 Sorcery Points to activate it. While Innate Sorcery is active, you can use up to two Metamagic options on each spell you cast.', 'special', NULL, False),
    ('Sorcerer: Epic Boon', 'Sorcerer: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Sorcerer: Arcane Apotheosis', 'Sorcerer: Arcane Apotheosis', 'While Innate Sorcery is active, you can use one Metamagic option on each of your turns without spending Sorcery Points on it.', 'special', NULL, False),
    ('Sorcerer (Aberrant Sorcery): Psionic Spells', 'Sorcerer (Aberrant Sorcery): Psionic Spells', 'Always prepare Mind Sliver, Arms of Hadar, Calm Emotions, Detect Thoughts, and Dissonant Whispers; later add Hunger of Hadar, Sending, Evard''s Black Tentacles, Summon Aberration, Rary''s Telepathic Bond, and Telekinesis.', 'special', NULL, False),
    ('Sorcerer (Aberrant Sorcery): Telepathic Speech', 'Sorcerer (Aberrant Sorcery): Telepathic Speech', 'Bonus Action to form a telepathic link with a creature you can see within 30ft.', 'special', 'While active ({level} minutes).', False),
    ('Sorcerer (Aberrant Sorcery): Psionic Sorcery', 'Sorcerer (Aberrant Sorcery): Psionic Sorcery', 'When you cast a level 1+ Psionic Spell, you can spend Sorcery Points equal to the spell''s level instead of using a slot. If you do, the spell needs no Verbal or Somatic components and no Material components unless consumed or costly.', 'special', NULL, False),
    ('Sorcerer (Aberrant Sorcery): Psychic Defenses', 'Sorcerer (Aberrant Sorcery): Psychic Defenses', 'You have resistance to psychic damage and advantage on saves vs being charmed or frightened.', 'damage_adjustment', NULL, False),
    ('Sorcerer (Aberrant Sorcery): Revelation in Flesh', 'Sorcerer (Aberrant Sorcery): Revelation in Flesh', 'Bonus Action to spend Sorcery Points and transform your body for 10 minutes, choosing options such as aquatic adaptation, flight, seeing invisible creatures, or squeezing through narrow spaces.', 'special', 'While active (10 minutes).', False),
    ('Sorcerer (Aberrant Sorcery): Warping Implosion', 'Sorcerer (Aberrant Sorcery): Warping Implosion', 'Magic Action to teleport up to 120 feet, then force creatures within 30 feet of your previous space to save against Force damage and being pulled inward. Refresh after a Long Rest or by spending 5 Sorcery Points.', 'special', NULL, False),
    ('Sorcerer (Clockwork Sorcery): Clockwork Spells', 'Sorcerer (Clockwork Sorcery): Clockwork Spells', 'Always prepare Aid, Alarm, Lesser Restoration, and Protection from Evil and Good; later add Dispel Magic, Protection from Energy, Freedom of Movement, Summon Construct, Greater Restoration, and Wall of Force.', 'special', NULL, False),
    ('Sorcerer (Clockwork Sorcery): Restore Balance', 'Sorcerer (Clockwork Sorcery): Restore Balance', 'Reaction to prevent a creature within 60ft from having Advantage or Disadvantage on a roll.', 'special', NULL, False),
    ('Sorcerer (Clockwork Sorcery): Bastion of Law', 'Sorcerer (Clockwork Sorcery): Bastion of Law', 'Magic Action to spend 1 to 5 Sorcery Points and create a ward of d8s around yourself or another visible creature within 30 feet. The ward can spend dice to reduce damage.', 'special', NULL, False),
    ('Sorcerer (Clockwork Sorcery): Trance of Order', 'Sorcerer (Clockwork Sorcery): Trance of Order', 'Bonus Action to enter a 1-minute state in which attacks against you cannot benefit from Advantage and you can treat a d20 roll of 9 or lower as a 10 on D20 Tests. Refresh after a Long Rest or by spending 5 Sorcery Points.', 'special', 'While active (1 minute).', False),
    ('Sorcerer (Clockwork Sorcery): Clockwork Cavalcade', 'Sorcerer (Clockwork Sorcery): Clockwork Cavalcade', 'Magic Action to summon spirits of order in a 30-foot Cube, restoring up to 100 HP, repairing objects, and ending level 6 or lower spells on chosen creatures or objects. Refresh after a Long Rest or by spending 7 Sorcery Points.', 'special', NULL, False),
    ('Sorcerer (Draconic Sorcery): Draconic Resilience', 'Sorcerer (Draconic Sorcery): Draconic Resilience', 'Your HP maximum increases by 3 and then by 1 whenever you gain another Sorcerer level. While unarmored, your base AC equals 10 + Dexterity modifier + Charisma modifier.', 'modifier', 'Conditions: no_armor.', False),
    ('Sorcerer (Draconic Sorcery): Draconic Resilience: Hit Points', 'Sorcerer (Draconic Sorcery): Draconic Resilience: Hit Points', 'Your HP maximum increases by 3 and then by 1 whenever you gain another Sorcerer level.', 'special', NULL, False),
    ('Sorcerer (Draconic Sorcery): Draconic Spells', 'Sorcerer (Draconic Sorcery): Draconic Spells', 'Always prepare Alter Self, Chromatic Orb, Command, and Dragon''s Breath; later add Fear, Fly, Arcane Eye, Charm Monster, Legend Lore, and Summon Dragon.', 'special', NULL, False),
    ('Sorcerer (Draconic Sorcery): Elemental Affinity', 'Sorcerer (Draconic Sorcery): Elemental Affinity', 'Choose Acid, Cold, Fire, Lightning, or Poison as your draconic affinity. Gain Resistance to that type, and add Charisma to one damage roll of spells you cast that deal it.', 'special', NULL, True),
    ('Sorcerer (Draconic Sorcery): Dragon Wings', 'Sorcerer (Draconic Sorcery): Dragon Wings', 'Bonus Action to manifest draconic wings for 1 hour, gaining a 60-foot Fly Speed. Refresh after a Long Rest or by spending 3 Sorcery Points.', 'special', 'While active (1 hour).', False),
    ('Sorcerer (Draconic Sorcery): Dragon Companion', 'Sorcerer (Draconic Sorcery): Dragon Companion', 'Cast Summon Dragon without a Material component and once per Long Rest without a spell slot. When you cast it, you can remove Concentration and reduce the duration to 1 minute.', 'special', NULL, False),
    ('Sorcerer (Wild Magic Sorcery): Tides of Chaos', 'Sorcerer (Wild Magic Sorcery): Tides of Chaos', 'Gain Advantage on one D20 Test before rolling. Before you can use it again, you must finish a Long Rest or cast a Sorcerer spell with a spell slot, which automatically triggers a Wild Magic Surge roll.', 'special', NULL, False),
    ('Sorcerer (Wild Magic Sorcery): Wild Magic Surge', 'Sorcerer (Wild Magic Sorcery): Wild Magic Surge', 'Once per turn after casting a Sorcerer spell with a spell slot, roll 1d20. On a 20, roll on the Wild Magic Surge table.', 'special', NULL, False),
    ('Sorcerer (Wild Magic Sorcery): Bend Luck', 'Sorcerer (Wild Magic Sorcery): Bend Luck', 'Reaction after a visible creature rolls a D20 Test; spend 1 Sorcery Point to add or subtract 1d4 from the roll.', 'special', NULL, False),
    ('Sorcerer (Wild Magic Sorcery): Controlled Chaos', 'Sorcerer (Wild Magic Sorcery): Controlled Chaos', 'Whenever you roll on the Wild Magic Surge table, you can roll twice and use either result.', 'special', NULL, False),
    ('Sorcerer (Wild Magic Sorcery): Tamed Surge', 'Sorcerer (Wild Magic Sorcery): Tamed Surge', 'Immediately after casting a Sorcerer spell with a spell slot, choose an effect from the Wild Magic Surge table instead of rolling, except the final row. Refresh after a Long Rest.', 'special', NULL, False),
    ('Warlock: Eldritch Invocations', 'Warlock: Eldritch Invocations', 'Gain one Eldritch Invocation, such as Pact of the Tome. Gain more invocations as you gain Warlock levels, and replace one whenever you gain a Warlock level.', 'special', NULL, True),
    ('Warlock: Pact Magic', 'Warlock: Pact Magic', 'Cast prepared Warlock spells using Charisma. You start with two Warlock cantrips and two level 1 prepared spells, use an Arcane Focus, and regain Pact Magic slots on a Short or Long Rest.', 'special', NULL, False),
    ('Warlock: Magical Cunning', 'Warlock: Magical Cunning', 'Perform a 1-minute rite to regain expended Pact Magic slots, up to half your maximum slots rounded up. Refresh after a Long Rest.', 'special', NULL, False),
    ('Warlock: Contact Patron', 'Warlock: Contact Patron', 'Always prepare Contact Other Plane. Cast it once per Long Rest without a spell slot to contact your patron, automatically succeeding on the spell''s saving throw.', 'special', NULL, False),
    ('Warlock: Mystic Arcanum', 'Warlock: Mystic Arcanum', 'Choose one level 9 Warlock spell as an arcanum. Cast it once without a spell slot, regaining the use after a Long Rest.', 'special', NULL, False),
    ('Warlock: Epic Boon', 'Warlock: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Warlock: Eldritch Master', 'Warlock: Eldritch Master', 'When you use Magical Cunning, you regain all expended Pact Magic slots.', 'special', NULL, False),
    ('Warlock (Archfey Patron): Archfey Spells', 'Warlock (Archfey Patron): Archfey Spells', 'Always prepare Calm Emotions, Faerie Fire, Misty Step, Phantasmal Force, and Sleep; later add Blink, Plant Growth, Dominate Beast, Greater Invisibility, Dominate Person, and Seeming.', 'special', NULL, False),
    ('Warlock (Archfey Patron): Steps of the Fey', 'Warlock (Archfey Patron): Steps of the Fey', 'Cast Misty Step without a spell slot a number of times equal to your Charisma modifier per Long Rest. When you cast it, add Refreshing Step or Taunting Step.', 'special', 'While active (Instant).', False),
    ('Warlock (Archfey Patron): Misty Escape', 'Warlock (Archfey Patron): Misty Escape', 'Cast Misty Step as a Reaction when you take damage. Add Disappearing Step and Dreadful Step to your Steps of the Fey options.', 'special', NULL, False),
    ('Warlock (Archfey Patron): Beguiling Defenses', 'Warlock (Archfey Patron): Beguiling Defenses', 'Gain Immunity to Charmed. When a visible creature hits you, use a Reaction to halve the damage and potentially deal Psychic damage back. Refresh after a Long Rest or by expending a Pact Magic slot.', 'special', NULL, False),
    ('Warlock (Archfey Patron): Bewitching Magic', 'Warlock (Archfey Patron): Bewitching Magic', 'Immediately after casting an Enchantment or Illusion spell using an action and a spell slot, cast Misty Step as part of the same action without a spell slot.', 'special', NULL, False),
    ('Warlock (Celestial Patron): Celestial Spells', 'Warlock (Celestial Patron): Celestial Spells', 'Always prepare Aid, Cure Wounds, Guiding Bolt, Lesser Restoration, Light, and Sacred Flame; later add Daylight, Revivify, Guardian of Faith, Wall of Fire, Greater Restoration, and Summon Celestial.', 'special', NULL, False),
    ('Warlock (Celestial Patron): Healing Light', 'Warlock (Celestial Patron): Healing Light', 'Gain a pool of d6s equal to 1 + Warlock level. As a Bonus Action, heal yourself or a visible creature within 60 feet, spending up to Charisma modifier dice.', 'special', NULL, False),
    ('Warlock (Celestial Patron): Radiant Soul', 'Warlock (Celestial Patron): Radiant Soul', 'Gain Resistance to Radiant damage. Once per turn when a spell you cast deals Radiant or Fire damage, add Charisma to that damage against one target.', 'damage_adjustment', NULL, False),
    ('Warlock (Celestial Patron): Celestial Resilience', 'Warlock (Celestial Patron): Celestial Resilience', 'Gain Temporary Hit Points when you use Magical Cunning or finish a Short or Long Rest. Up to five visible creatures also gain a smaller amount.', 'special', NULL, False),
    ('Warlock (Celestial Patron): Searing Vengeance', 'Warlock (Celestial Patron): Searing Vengeance', 'When you or an ally within 60 feet is about to make a Death Saving Throw, restore half that creature''s HP maximum, end Prone, and sear nearby chosen creatures with Radiant damage and Blinded. Once per Long Rest.', 'special', NULL, False),
    ('Warlock (Fiend Patron): Dark One''s Blessing', 'Warlock (Fiend Patron): Dark One''s Blessing', 'When you reduce an enemy to 0 HP, or an enemy within 10 feet drops to 0 HP, gain Temporary Hit Points equal to Charisma modifier + Warlock level.', 'special', NULL, False),
    ('Warlock (Fiend Patron): Fiend Spells', 'Warlock (Fiend Patron): Fiend Spells', 'Always prepare Burning Hands, Command, Scorching Ray, and Suggestion; later add Fireball, Stinking Cloud, Fire Shield, Wall of Fire, Geas, and Insect Plague.', 'special', NULL, False),
    ('Warlock (Fiend Patron): Dark One''s Own Luck', 'Warlock (Fiend Patron): Dark One''s Own Luck', 'When you make an ability check or saving throw, add 1d10 after seeing the roll but before its effects. Uses equal Charisma modifier per Long Rest.', 'special', NULL, False),
    ('Warlock (Fiend Patron): Fiendish Resilience', 'Warlock (Fiend Patron): Fiendish Resilience', 'After each Short or Long Rest, choose one damage type other than Force and gain Resistance to it until you choose again.', 'special', NULL, True),
    ('Warlock (Fiend Patron): Hurl Through Hell', 'Warlock (Fiend Patron): Hurl Through Hell', 'Once per turn when you hit a creature, force a Charisma save or send it through the Lower Planes. It takes 8d10 Psychic damage if not a Fiend and is Incapacitated until it returns. Refresh after a Long Rest or by expending a Pact Magic slot.', 'special', NULL, False),
    ('Warlock (Great Old One Patron): Awakened Mind', 'Warlock (Great Old One Patron): Awakened Mind', 'Bonus Action to form a telepathic bond with a visible creature within 30 feet for minutes equal to your Warlock level, working over miles equal to your Charisma modifier.', 'special', 'While active ({level} minutes).', False),
    ('Warlock (Great Old One Patron): Great Old One Spells', 'Warlock (Great Old One Patron): Great Old One Spells', 'Always prepare Detect Thoughts, Dissonant Whispers, Phantasmal Force, and Tasha''s Hideous Laughter; later add Clairvoyance, Hunger of Hadar, Confusion, Summon Aberration, Modify Memory, and Telekinesis.', 'special', NULL, False),
    ('Warlock (Great Old One Patron): Psychic Spells', 'Warlock (Great Old One Patron): Psychic Spells', 'When a Warlock spell you cast deals damage, you can make it Psychic damage. When you cast an Enchantment or Illusion Warlock spell, it needs no Verbal or Somatic components.', 'special', NULL, False),
    ('Warlock (Great Old One Patron): Clairvoyant Combatant', 'Warlock (Great Old One Patron): Clairvoyant Combatant', 'When you form an Awakened Mind bond, force the target to make a Wisdom save. On a failure, it has Disadvantage against you and you have Advantage against it for the bond''s duration. Refresh after a Short or Long Rest or by expending a Pact Magic slot.', 'special', 'While active (Awakened Mind bond).', False),
    ('Warlock (Great Old One Patron): Eldritch Hex', 'Warlock (Great Old One Patron): Eldritch Hex', 'Always prepare Hex. When you cast it and choose an ability, the target also has Disadvantage on saving throws with that ability.', 'special', NULL, False),
    ('Warlock (Great Old One Patron): Thought Shield', 'Warlock (Great Old One Patron): Thought Shield', 'Your thoughts cannot be read unless you allow it. Gain Resistance to Psychic damage, and creatures that deal Psychic damage to you take the same amount.', 'damage_adjustment', NULL, False),
    ('Warlock (Great Old One Patron): Create Thrall', 'Warlock (Great Old One Patron): Create Thrall', 'When you cast Summon Aberration, you can remove Concentration and reduce its duration to 1 minute. The Aberration gains Temporary Hit Points and deals extra Psychic damage to your Hex target once per turn.', 'special', NULL, False),
    ('Wizard: Arcane Recovery', 'Wizard: Arcane Recovery', 'Once per Long Rest when you finish a Short Rest, recover expended spell slots with a combined level up to half your Wizard level, rounded up, none level 6 or higher.', 'special', NULL, False),
    ('Wizard: Ritual Adept', 'Wizard: Ritual Adept', 'Cast a spell as a ritual if it has the Ritual tag and is in your spellbook. The spell does not need to be prepared, but you must read from the book.', 'special', NULL, False),
    ('Wizard: Spellcasting', 'Wizard: Spellcasting', 'Cast prepared Wizard spells using Intelligence. You start with three Wizard cantrips, a spellbook containing six level 1 Wizard spells, and four prepared level 1 spells. Use an Arcane Focus or your spellbook as a spellcasting focus.', 'special', NULL, False),
    ('Wizard: Scholar', 'Wizard: Scholar', 'Choose one proficient skill from Arcana, History, Investigation, Medicine, Nature, or Religion. You gain Expertise in that skill.', 'special', NULL, True),
    ('Wizard: Memorize Spell', 'Wizard: Memorize Spell', 'Whenever you finish a Short Rest, study your spellbook and replace one prepared level 1+ Wizard spell with another level 1+ spell from the book.', 'special', NULL, False),
    ('Wizard: Spell Mastery', 'Wizard: Spell Mastery', 'Choose a 1st-level and 2nd-level spell to cast at their lowest level without expending a spell slot.', 'special', NULL, False),
    ('Wizard: Epic Boon', 'Wizard: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.', 'special', NULL, False),
    ('Wizard: Signature Spells', 'Wizard: Signature Spells', 'Choose two 3rd-level spells as your signature spells, which you can cast without a slot once per rest.', 'special', NULL, False),
    ('Wizard (Abjurer): Abjuration Savant', 'Wizard (Abjurer): Abjuration Savant', 'Add two Abjuration Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Abjuration Wizard spell of that level to your spellbook for free.', 'special', NULL, False),
    ('Wizard (Abjurer): Arcane Ward', 'Wizard (Abjurer): Arcane Ward', 'When you cast an Abjuration spell with a spell slot, create a ward with HP equal to twice your Wizard level plus Intelligence. The ward absorbs damage and can be restored by casting Abjuration spells or expending spell slots.', 'special', NULL, False),
    ('Wizard (Abjurer): Projected Ward', 'Wizard (Abjurer): Projected Ward', 'Reaction to use your Arcane Ward to absorb damage for a creature within 30ft.', 'special', NULL, False),
    ('Wizard (Abjurer): Spell Breaker', 'Wizard (Abjurer): Spell Breaker', 'Always prepare Counterspell and Dispel Magic. Cast Dispel Magic as a Bonus Action, add Proficiency Bonus to its check, and do not expend a spell slot when Counterspell or Dispel Magic fails to stop a spell.', 'special', NULL, False),
    ('Wizard (Abjurer): Spell Resistance', 'Wizard (Abjurer): Spell Resistance', 'Gain advantage on saving throws against spells and resistance to damage from spells.', 'special', NULL, False),
    ('Wizard (Diviner): Divination Savant', 'Wizard (Diviner): Divination Savant', 'Add two Divination Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Divination Wizard spell of that level to your spellbook for free.', 'special', NULL, False),
    ('Wizard (Diviner): Portent', 'Wizard (Diviner): Portent', 'After each Long Rest, roll two d20s and record them. Before a visible creature makes a D20 Test, replace the roll with one recorded result, using each result once.', 'special', 'While active (for one triggering D20 Test).', False),
    ('Wizard (Diviner): Expert Divination', 'Wizard (Diviner): Expert Divination', 'When you cast a divination spell of 2nd level or higher, regain a lower-level spell slot.', 'special', NULL, False),
    ('Wizard (Diviner): The Third Eye', 'Wizard (Diviner): The Third Eye', 'Bonus Action to gain one benefit until your next Short or Long Rest: 120-foot Darkvision, read any language, or cast See Invisibility without a spell slot.', 'special', 'While active (until your next Short or Long Rest).', False),
    ('Wizard (Diviner): Greater Portent', 'Wizard (Diviner): Greater Portent', 'You now roll three d20s for your Portent feature instead of two.', 'special', NULL, False),
    ('Wizard (Evoker): Evocation Savant', 'Wizard (Evoker): Evocation Savant', 'Add two Evocation Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Evocation Wizard spell of that level to your spellbook for free.', 'special', NULL, False),
    ('Wizard (Evoker): Potent Cantrip', 'Wizard (Evoker): Potent Cantrip', 'When you cast a damaging cantrip at a creature and miss or the creature succeeds on the save, it still takes half the cantrip''s damage but no other effect.', 'special', NULL, False),
    ('Wizard (Evoker): Sculpt Spells', 'Wizard (Evoker): Sculpt Spells', 'When you cast an Evocation spell that affects other visible creatures, choose a number of them equal to 1 plus the spell''s level. They automatically succeed on saves and take no damage on successful saves.', 'special', NULL, False),
    ('Wizard (Evoker): Empowered Evocation', 'Wizard (Evoker): Empowered Evocation', 'Add your Intelligence modifier to one damage roll of any wizard evocation spell.', 'special', NULL, False),
    ('Wizard (Evoker): Overchannel', 'Wizard (Evoker): Overchannel', 'Deal maximum damage with a wizard spell of 1st through 5th level, but take necrotic damage if used again.', 'special', NULL, False),
    ('Wizard (Illusionist): Illusion Savant', 'Wizard (Illusionist): Illusion Savant', 'Add two Illusion Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Illusion Wizard spell of that level to your spellbook for free.', 'special', NULL, False),
    ('Wizard (Illusionist): Improved Illusions', 'Wizard (Illusionist): Improved Illusions', 'Cast Illusion spells without Verbal components, and increase their range by 60 feet if their range is 10 feet or more. You also know Minor Illusion, can cast it as a Bonus Action, and can create both sound and image with it.', 'special', NULL, False),
    ('Wizard (Illusionist): Phantasmal Creatures', 'Wizard (Illusionist): Phantasmal Creatures', 'Always prepare Summon Beast and Summon Fey. When you cast either, you can make it Illusion, and once per Long Rest cast the Illusion version without a slot with the summoned creature at half HP.', 'special', NULL, False),
    ('Wizard (Illusionist): Illusory Self', 'Wizard (Illusionist): Illusory Self', 'Reaction to create an illusory duplicate that causes an attack to automatically miss.', 'special', NULL, False),
    ('Wizard (Illusionist): Illusory Reality', 'Wizard (Illusionist): Illusory Reality', 'Bonus Action to make one object in your illusion become real and tangible for 1 minute.', 'special', 'While active (1 minute).', False);

