INSERT INTO trait_options (trait_id, option_group, name, description, sort_order)
SELECT t.id, ot.option_group, ot.option_name, ot.description, ot.sort_order
FROM _import_class_trait_option_data ot
JOIN traits t ON t.name = ot.trait_name
ON CONFLICT (trait_id, option_group, name) DO UPDATE SET
    description = EXCLUDED.description,
    sort_order = EXCLUDED.sort_order;

