CREATE TEMP TABLE _import_class_condition_adjustment_data (
    effect_name TEXT NOT NULL,
    status_name TEXT NOT NULL,
    adjustment_type TEXT NOT NULL,
    scope_text TEXT,
    PRIMARY KEY (effect_name, status_name, adjustment_type)
) ON COMMIT DROP;

-- No rows for _import_class_condition_adjustment_data.

CREATE TEMP TABLE _import_class_effect_proficiency_data (
    effect_name TEXT NOT NULL,
    proficiency_type TEXT NOT NULL,
    name TEXT,
    requires_choice BOOLEAN NOT NULL DEFAULT FALSE,
    choice_count INT NOT NULL DEFAULT 1,
    notes TEXT,
    PRIMARY KEY (effect_name, proficiency_type)
) ON COMMIT DROP;

