INSERT INTO effects (
    trait_id,
    name,
    description,
    effect_type,
    duration_text,
    requires_choice
)
SELECT
    t.id,
    ed.effect_name,
    ed.description,
    ed.effect_type,
    ed.duration_text,
    ed.requires_choice
FROM _import_class_effect_data ed
JOIN traits t ON t.name = ed.trait_name
WHERE NOT EXISTS (
    SELECT 1 FROM effects e
    WHERE e.trait_id = t.id AND e.name = ed.effect_name
);

UPDATE effects e
SET
    description = ed.description,
    effect_type = ed.effect_type,
    duration_text = ed.duration_text,
    requires_choice = ed.requires_choice
FROM _import_class_effect_data ed
JOIN traits t ON t.name = ed.trait_name
WHERE e.trait_id = t.id AND e.name = ed.effect_name;

INSERT INTO effects (
    trait_option_id,
    name,
    description,
    effect_type,
    duration_text,
    requires_choice
)
SELECT
    tro.id,
    oed.effect_name,
    oed.description,
    oed.effect_type,
    oed.duration_text,
    oed.requires_choice
FROM _import_class_option_effect_data oed
JOIN traits t ON t.name = oed.trait_name
JOIN trait_options tro ON tro.trait_id = t.id
    AND tro.option_group = oed.option_group
    AND tro.name = oed.option_name
WHERE NOT EXISTS (
    SELECT 1 FROM effects e
    WHERE e.trait_option_id = tro.id AND e.name = oed.effect_name
);

UPDATE effects e
SET
    description = oed.description,
    effect_type = oed.effect_type,
    duration_text = oed.duration_text,
    requires_choice = oed.requires_choice
FROM _import_class_option_effect_data oed
JOIN traits t ON t.name = oed.trait_name
JOIN trait_options tro ON tro.trait_id = t.id
    AND tro.option_group = oed.option_group
    AND tro.name = oed.option_name
WHERE e.trait_option_id = tro.id AND e.name = oed.effect_name;

CREATE TEMP TABLE _import_class_effects ON COMMIT DROP AS
SELECT e.id AS effect_id, ed.effect_name
FROM _import_class_effect_data ed
JOIN traits t ON t.name = ed.trait_name
JOIN effects e ON e.trait_id = t.id AND e.name = ed.effect_name
UNION ALL
SELECT e.id AS effect_id, oed.effect_name
FROM _import_class_option_effect_data oed
JOIN traits t ON t.name = oed.trait_name
JOIN trait_options tro ON tro.trait_id = t.id
    AND tro.option_group = oed.option_group
    AND tro.name = oed.option_name
JOIN effects e ON e.trait_option_id = tro.id AND e.name = oed.effect_name;

DELETE FROM effect_modifiers em
USING _import_class_effects ice
WHERE em.effect_id = ice.effect_id;

INSERT INTO effect_modifiers (effect_id, affected_stat, operation, modifier_value)
SELECT ice.effect_id, em.affected_stat, em.operation, em.modifier_value
FROM _import_class_effect_modifier_data em
JOIN _import_class_effects ice ON ice.effect_name = em.effect_name
ON CONFLICT (effect_id, affected_stat, operation) DO UPDATE SET
    modifier_value = EXCLUDED.modifier_value;

DELETE FROM effect_damage_adjustments eda
USING _import_class_effects ice, _import_class_damage_adjustment_data da
WHERE eda.effect_id = ice.effect_id AND ice.effect_name = da.effect_name;

INSERT INTO effect_damage_adjustments (effect_id, damage_type_id, adjustment_type, scope_text)
SELECT ice.effect_id, dt.id, da.adjustment_type, da.scope_text
FROM _import_class_damage_adjustment_data da
JOIN _import_class_effects ice ON ice.effect_name = da.effect_name
JOIN damage_types dt ON dt.name = da.damage_type;

DELETE FROM effect_condition_adjustments eca
USING _import_class_effects ice, _import_class_condition_adjustment_data ca
WHERE eca.effect_id = ice.effect_id AND ice.effect_name = ca.effect_name;

INSERT INTO effect_condition_adjustments (effect_id, status_id, adjustment_type, scope_text)
SELECT ice.effect_id, s.id, ca.adjustment_type, ca.scope_text
FROM _import_class_condition_adjustment_data ca
JOIN _import_class_effects ice ON ice.effect_name = ca.effect_name
JOIN statuses s ON s.name = ca.status_name;

DELETE FROM effect_proficiencies ep
USING _import_class_effects ice
WHERE ep.effect_id = ice.effect_id;

INSERT INTO effect_proficiencies (effect_id, proficiency_type, name, requires_choice, choice_count, notes)
SELECT ice.effect_id, ep.proficiency_type, ep.name, ep.requires_choice, ep.choice_count, ep.notes
FROM _import_class_effect_proficiency_data ep
JOIN _import_class_effects ice ON ice.effect_name = ep.effect_name;

COMMIT;
